"use client"

import * as React from "react"

import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip"
import { cn } from "@/lib/utils"

/**
 * Wraps cell content in a click-to-copy affordance with a transient "Copied"
 * tooltip. Uses `navigator.clipboard` (secure-context only) with a
 * `document.execCommand` fallback, both guarded for SSR.
 */
export function ClickToCopy({
  value,
  copyLabel,
  copiedLabel,
  children,
}: {
  value: string
  copyLabel: string
  copiedLabel: string
  children: React.ReactNode
}) {
  const [copied, setCopied] = React.useState(false)
  const timer = React.useRef<ReturnType<typeof setTimeout> | undefined>(
    undefined
  )

  React.useEffect(() => () => clearTimeout(timer.current), [])

  const copy = async () => {
    const ok = await copyText(value)
    if (!ok) return
    setCopied(true)
    clearTimeout(timer.current)
    timer.current = setTimeout(() => setCopied(false), 1200)
  }

  return (
    <Tooltip open={copied || undefined}>
      <TooltipTrigger asChild>
        <button
          type="button"
          onClick={copy}
          aria-label={copyLabel}
          className={cn(
            "-mx-1 rounded-sm px-1 text-left transition-colors outline-none hover:bg-muted focus-visible:ring-2 focus-visible:ring-ring/40"
          )}
        >
          {children}
        </button>
      </TooltipTrigger>
      <TooltipContent>{copied ? copiedLabel : copyLabel}</TooltipContent>
    </Tooltip>
  )
}

async function copyText(text: string): Promise<boolean> {
  if (typeof navigator !== "undefined" && navigator.clipboard?.writeText) {
    try {
      await navigator.clipboard.writeText(text)
      return true
    } catch {
      // fall through to legacy path
    }
  }
  if (typeof document === "undefined") return false
  try {
    const el = document.createElement("textarea")
    el.value = text
    el.style.position = "fixed"
    el.style.opacity = "0"
    document.body.appendChild(el)
    el.select()
    const ok = document.execCommand("copy")
    document.body.removeChild(el)
    return ok
  } catch {
    return false
  }
}

import type { CSSProperties } from "react"
import type { Column, RowData, Table } from "@tanstack/react-table"

/**
 * Sticky positioning for a pinned column. Offsets come from TanStack
 * (`getStart`/`getAfter`) so multiple pinned columns stack correctly.
 */
export function getColumnPinningStyle<TData extends RowData, TValue>(
  column: Column<TData, TValue>
): CSSProperties {
  const pinned = column.getIsPinned()
  if (!pinned) return {}
  return {
    position: "sticky",
    zIndex: 2,
    ...(pinned === "left"
      ? { left: column.getStart("left") }
      : { right: column.getAfter("right") }),
  }
}

/**
 * Edge-shadow class for the boundary pinned columns (last left / first right),
 * built from `--border` (via a utility) so it reads in light and dark.
 */
export function getColumnPinningClass<TData extends RowData, TValue>(
  column: Column<TData, TValue>
): string {
  const pinned = column.getIsPinned()
  if (!pinned) return ""
  const isLastLeft =
    pinned === "left" && column.getIsLastColumn("left")
  const isFirstRight =
    pinned === "right" && column.getIsFirstColumn("right")
  if (isLastLeft) {
    return "after:pointer-events-none after:absolute after:inset-y-0 after:-right-px after:w-2 after:translate-x-full after:bg-gradient-to-r after:from-border/60 after:to-transparent"
  }
  if (isFirstRight) {
    return "before:pointer-events-none before:absolute before:inset-y-0 before:-left-px before:w-2 before:-translate-x-full before:bg-gradient-to-l before:from-border/60 before:to-transparent"
  }
  return ""
}

/**
 * CSS custom properties holding each column's size, set once on the table
 * element. Cells read them via `width: calc(var(--col-…-size) * 1px)` so a
 * resize drag updates a variable instead of re-rendering every cell.
 */
export function getColumnSizeVars<TData extends RowData>(
  table: Table<TData>
): Record<string, string> {
  const headers = table.getFlatHeaders()
  const vars: Record<string, string> = {}
  for (const header of headers) {
    vars[`--header-${header.id}-size`] = `${header.getSize()}`
    vars[`--col-${header.column.id}-size`] = `${header.column.getSize()}`
  }
  return vars
}

export function getColumnWidthStyle(columnId: string): CSSProperties {
  return { width: `calc(var(--col-${columnId}-size) * 1px)` }
}

"use client"

import * as React from "react"

import type { DataTableIcons } from "./icons"
import type { DataTableLocalization } from "./localization"

/**
 * App-wide defaults for every table below it. `useDataTable` merges these
 * between the built-in defaults and per-call options:
 *   defaults  <  provider  <  useDataTable({ icons, localization })
 * Handy for setting one icon library or locale across a whole app without
 * passing it to each table.
 */
export interface DataTableConfigContextValue {
  icons?: Partial<DataTableIcons>
  localization?: Partial<DataTableLocalization>
}

const DataTableConfigContext =
  React.createContext<DataTableConfigContextValue>({})

export function DataTableConfigProvider({
  icons,
  localization,
  children,
}: DataTableConfigContextValue & { children: React.ReactNode }) {
  const value = React.useMemo(
    () => ({ icons, localization }),
    [icons, localization]
  )
  return (
    <DataTableConfigContext.Provider value={value}>
      {children}
    </DataTableConfigContext.Provider>
  )
}

export function useDataTableConfigContext(): DataTableConfigContextValue {
  return React.useContext(DataTableConfigContext)
}

"use client"

import type { Column, RowData } from "@tanstack/react-table"

import { Button } from "@/components/ui/button"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip"
import { cn } from "@/lib/utils"

import type { DataTableInstance } from "./types"

interface DataTableColumnActionsProps<TData extends RowData, TValue> {
  column: Column<TData, TValue>
  table: DataTableInstance<TData>
  className?: string
}

/**
 * The MRT-signature per-column menu: a vertical-dots ghost button after the
 * header label that opens sort / hide / filter actions. Items render only when
 * the column supports them, so an ID column with sorting/filtering off shows
 * just the hide controls.
 */
export function DataTableColumnActions<TData extends RowData, TValue>({
  column,
  table,
  className,
}: DataTableColumnActionsProps<TData, TValue>) {
  const {
    localization,
    icons,
    setShowColumnFilters,
    enableColumnPinning,
    enableGrouping,
    renderColumnActionsMenuItems,
  } = table.cnTable
  const canSort = column.getCanSort()
  const canHide = column.getCanHide()
  const canFilter = column.getCanFilter()
  const canPin = enableColumnPinning && column.getCanPin()
  const canGroup = enableGrouping && column.getCanGroup()
  const isGrouped = column.getIsGrouped()
  const sorted = column.getIsSorted()
  const pinned = column.getIsPinned()
  const hasFilter = column.getFilterValue() != null

  return (
    <DropdownMenu>
      <Tooltip>
        <TooltipTrigger asChild>
          <DropdownMenuTrigger asChild>
            <Button
              variant="ghost"
              size="icon"
              aria-label={localization.columnActions}
              className={cn(
                "size-7 opacity-70 transition-opacity group-hover/th:opacity-100 focus-visible:opacity-100 data-[state=open]:opacity-100",
                className
              )}
            >
              <icons.columnActions />
            </Button>
          </DropdownMenuTrigger>
        </TooltipTrigger>
        <TooltipContent>{localization.columnActions}</TooltipContent>
      </Tooltip>
      <DropdownMenuContent align="start" className="w-48">
        {canSort && (
          <>
            <DropdownMenuItem
              onClick={() => column.toggleSorting(false)}
              disabled={sorted === "asc"}
            >
              <icons.sortAscending />
              {localization.sortAscending}
            </DropdownMenuItem>
            <DropdownMenuItem
              onClick={() => column.toggleSorting(true)}
              disabled={sorted === "desc"}
            >
              <icons.sortDescending />
              {localization.sortDescending}
            </DropdownMenuItem>
            <DropdownMenuItem
              onClick={() => column.clearSorting()}
              disabled={!sorted}
            >
              <icons.clearAll />
              {localization.clearSort}
            </DropdownMenuItem>
          </>
        )}

        {canFilter && (
          <>
            {canSort && <DropdownMenuSeparator />}
            <DropdownMenuItem onClick={() => setShowColumnFilters(true)}>
              <icons.filter />
              {localization.filterByColumn(getColumnLabel(column))}
            </DropdownMenuItem>
            <DropdownMenuItem
              onClick={() => column.setFilterValue(undefined)}
              disabled={!hasFilter}
            >
              <icons.filterOff />
              {localization.clearFilter}
            </DropdownMenuItem>
          </>
        )}

        {canHide && (
          <>
            {(canSort || canFilter) && <DropdownMenuSeparator />}
            <DropdownMenuItem onClick={() => column.toggleVisibility(false)}>
              <icons.hide />
              {localization.hideColumn}
            </DropdownMenuItem>
            <DropdownMenuItem
              onClick={() => table.toggleAllColumnsVisible(true)}
            >
              <icons.clearAll />
              {localization.showAllColumns}
            </DropdownMenuItem>
          </>
        )}

        {canGroup && (
          <>
            {(canSort || canFilter || canHide) && <DropdownMenuSeparator />}
            <DropdownMenuItem onClick={() => column.toggleGrouping()}>
              <icons.group />
              {isGrouped
                ? localization.ungroupByColumn(getColumnLabel(column))
                : localization.groupByColumn(getColumnLabel(column))}
            </DropdownMenuItem>
          </>
        )}

        {canPin && (
          <>
            {(canSort || canFilter || canHide || canGroup) && (
              <DropdownMenuSeparator />
            )}
            <DropdownMenuItem
              onClick={() => column.pin("left")}
              disabled={pinned === "left"}
            >
              <icons.pin />
              {localization.pinToLeft}
            </DropdownMenuItem>
            <DropdownMenuItem
              onClick={() => column.pin("right")}
              disabled={pinned === "right"}
            >
              <icons.pin />
              {localization.pinToRight}
            </DropdownMenuItem>
            <DropdownMenuItem
              onClick={() => column.pin(false)}
              disabled={!pinned}
            >
              <icons.unpin />
              {localization.unpin}
            </DropdownMenuItem>
          </>
        )}

        {renderColumnActionsMenuItems && (
          <>
            {(canSort || canFilter || canHide || canGroup || canPin) && (
              <DropdownMenuSeparator />
            )}
            {renderColumnActionsMenuItems({
              column: column as Column<TData, unknown>,
              table,
            })}
          </>
        )}
      </DropdownMenuContent>
    </DropdownMenu>
  )
}

/** Best-effort human label for a column: explicit meta.label, else its id. */
export function getColumnLabel<TData extends RowData, TValue>(
  column: Column<TData, TValue>
): string {
  const meta = column.columnDef.meta
  if (meta?.label) return meta.label
  const header = column.columnDef.header
  if (typeof header === "string" && header.length > 0) return header
  return column.id
}

"use client"

import type { Header, RowData } from "@tanstack/react-table"

import { DataTableFilterModeMenu } from "./data-table-filter-mode-menu"
import {
  CheckboxFilterField,
  DateFilterField,
  DateRangeFilterField,
  MultiSelectFilterField,
  NumberFilterField,
  RangeSliderFilterField,
  SelectFilterField,
  TextFilterField,
  type FilterFieldProps,
} from "./data-table-filter-variants"
import type { DataTableInstance } from "./types"

interface DataTableColumnFilterProps<TData extends RowData, TValue> {
  header: Header<TData, TValue>
  table: DataTableInstance<TData>
}

/**
 * One filter-row field. Reads `column.meta.variant` and renders the matching
 * control, preceded by the filter-mode menu (where the variant supports modes).
 * `meta.renderColumnFilter` is an escape hatch for fully custom UI. Returns an
 * empty placeholder for non-filterable columns so the grid stays aligned.
 */
export function DataTableColumnFilter<TData extends RowData, TValue>({
  header,
  table,
}: DataTableColumnFilterProps<TData, TValue>) {
  const { column } = header

  if (header.isPlaceholder || !column.getCanFilter()) {
    return <div className="h-8" />
  }

  const custom = column.columnDef.meta?.renderColumnFilter
  if (custom) {
    return <>{custom({ column, table })}</>
  }

  return (
    <div className="flex items-center gap-0.5">
      <DataTableFilterModeMenu column={column} table={table} />
      <div className="min-w-0 flex-1">
        <FilterField column={column} table={table} />
      </div>
    </div>
  )
}

function FilterField<TData extends RowData, TValue>({
  column,
  table,
}: FilterFieldProps<TData, TValue>) {
  const variant = column.columnDef.meta?.variant ?? "text"
  switch (variant) {
    case "select":
      return <SelectFilterField column={column} table={table} />
    case "multi-select":
      return <MultiSelectFilterField column={column} table={table} />
    case "checkbox":
      return <CheckboxFilterField column={column} table={table} />
    case "range":
      return <NumberFilterField column={column} table={table} />
    case "range-slider":
      return <RangeSliderFilterField column={column} table={table} />
    case "date":
      return <DateFilterField column={column} table={table} />
    case "date-range":
      return <DateRangeFilterField column={column} table={table} />
    default:
      return <TextFilterField column={column} table={table} />
  }
}

"use client"

import {
  flexRender,
  type Header,
  type RowData,
} from "@tanstack/react-table"

import { Badge } from "@/components/ui/badge"
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip"
import { cn } from "@/lib/utils"

import { DataTableColumnActions, getColumnLabel } from "./data-table-column-actions"
import type { DataTableInstance } from "./types"

interface DataTableColumnHeaderProps<TData extends RowData, TValue> {
  header: Header<TData, TValue>
  table: DataTableInstance<TData>
}

const ALIGN_CLASS = {
  left: "justify-start text-left",
  center: "justify-center text-center",
  right: "justify-end text-right",
} as const

/**
 * Wraps every header cell with the MRT layout: label (sort trigger) · sort
 * indicator · multi-sort order badge · column-actions menu, left-aligned by
 * default. Clicking the label cycles asc → desc → none; shift-click multi-sorts
 * (both via TanStack's `getToggleSortingHandler`).
 */
export function DataTableColumnHeader<TData extends RowData, TValue>({
  header,
  table,
}: DataTableColumnHeaderProps<TData, TValue>) {
  const { column } = header
  const { localization, icons, enableColumnActions } = table.cnTable
  const align = column.columnDef.meta?.align ?? "left"

  const labelNode = header.isPlaceholder
    ? null
    : flexRender(column.columnDef.header, header.getContext())

  const canSort = column.getCanSort()
  const sorted = column.getIsSorted() // false | "asc" | "desc"
  const sortIndex = column.getSortIndex()
  const isMultiSort =
    table.getState().sorting.length > 1 && sortIndex >= 0

  const showActions =
    enableColumnActions &&
    !column.columnDef.meta?.disableColumnActions &&
    (canSort ||
      column.getCanHide() ||
      column.getCanFilter() ||
      (table.cnTable.enableColumnPinning && column.getCanPin()) ||
      (table.cnTable.enableGrouping && column.getCanGroup()))

  // Non-interactive header (e.g. the selection column): render content plainly.
  if (!canSort && !showActions) {
    return (
      <div className={cn("flex items-center gap-1", ALIGN_CLASS[align])}>
        {labelNode}
      </div>
    )
  }

  const sortTooltip = !sorted
    ? localization.sortByColumnAsc(getColumnLabel(column))
    : sorted === "asc"
      ? localization.sortByColumnDesc(getColumnLabel(column))
      : localization.clearSort

  return (
    <div
      className={cn(
        "group/th flex items-center gap-0.5",
        align === "right" && "flex-row-reverse",
        ALIGN_CLASS[align]
      )}
    >
      {canSort ? (
        <Tooltip>
          <TooltipTrigger asChild>
            <button
              type="button"
              onClick={column.getToggleSortingHandler()}
              aria-label={sortTooltip}
              className="-mx-1.5 flex items-center gap-1 rounded-sm px-1.5 py-1 text-xs font-medium tracking-wider uppercase whitespace-nowrap text-muted-foreground transition-colors outline-none hover:text-foreground focus-visible:ring-2 focus-visible:ring-ring/40 data-[sorted=true]:text-foreground"
              data-sorted={!!sorted}
            >
              <span>{labelNode}</span>
              <SortIndicator sorted={sorted} icons={icons} />
              {isMultiSort && (
                <Badge
                  variant="secondary"
                  className="ml-0.5 h-4 min-w-4 justify-center rounded-sm px-1 text-[10px] leading-none tabular-nums"
                >
                  {sortIndex + 1}
                </Badge>
              )}
            </button>
          </TooltipTrigger>
          <TooltipContent>{sortTooltip}</TooltipContent>
        </Tooltip>
      ) : (
        <span className="px-0 text-xs font-medium tracking-wider uppercase whitespace-nowrap">
          {labelNode}
        </span>
      )}

      {showActions && (
        <DataTableColumnActions
          column={column}
          table={table}
          className="-my-1"
        />
      )}
    </div>
  )
}

function SortIndicator({
  sorted,
  icons,
}: {
  sorted: false | "asc" | "desc"
  icons: DataTableInstance["cnTable"]["icons"]
}) {
  if (sorted === "asc") return <icons.sortAscending className="size-3.5" />
  if (sorted === "desc") return <icons.sortDescending className="size-3.5" />
  return (
    <icons.sortUnsorted className="size-3.5 opacity-50 transition-opacity group-hover/th:opacity-70" />
  )
}

"use client"

import * as React from "react"
import type { Header, Row, RowData } from "@tanstack/react-table"
import { useSortable } from "@dnd-kit/sortable"
import { CSS } from "@dnd-kit/utilities"

import { TableHead, TableRow } from "@/components/ui/table"
import { cn } from "@/lib/utils"

import { getColumnPinningClass, getColumnPinningStyle } from "./column-styles"
import { RowDragContext } from "./display-columns"
import type { DataTableInstance } from "./types"

/** Drag handle to grab the resize edge of a column header. */
export function ColumnResizeHandle<TData extends RowData, TValue>({
  header,
  table,
}: {
  header: Header<TData, TValue>
  table: DataTableInstance<TData>
}) {
  if (!header.column.getCanResize()) return null
  return (
    <span
      role="separator"
      aria-label={table.cnTable.localization.resizeColumn}
      onMouseDown={header.getResizeHandler()}
      onTouchStart={header.getResizeHandler()}
      onDoubleClick={() => header.column.resetSize()}
      className={cn(
        "absolute top-0 right-0 z-10 h-full w-1 cursor-col-resize touch-none select-none bg-transparent transition-colors hover:bg-border",
        header.column.getIsResizing() && "bg-primary"
      )}
    />
  )
}

/**
 * Header cell. `useSortable` is always called (disabled when ordering is off or
 * for display columns) to keep hook order stable. Applies pinning + width
 * styles, an optional drag grip, and the resize handle.
 */
export function DataTableHeadCell<TData extends RowData, TValue>({
  header,
  table,
  draggable,
  resizable,
  widthStyle,
  padding,
  children,
}: {
  header: Header<TData, TValue>
  table: DataTableInstance<TData>
  draggable: boolean
  resizable: boolean
  widthStyle: React.CSSProperties
  padding: string
  children: React.ReactNode
}) {
  const column = header.column
  const { attributes, listeners, setNodeRef, setActivatorNodeRef, transform, isDragging } =
    useSortable({ id: column.id, disabled: !draggable, data: { type: "column" } })

  const style: React.CSSProperties = {
    ...widthStyle,
    ...getColumnPinningStyle(column),
    transform: CSS.Translate.toString(transform),
    transition: "width 0.15s ease",
    opacity: isDragging ? 0.7 : undefined,
    zIndex: isDragging ? 30 : undefined,
  }

  return (
    <TableHead
      ref={setNodeRef}
      colSpan={header.colSpan}
      style={style}
      data-pinned={column.getIsPinned() || undefined}
      aria-sort={ariaSort(column.getIsSorted())}
      className={cn(
        "relative bg-background",
        padding,
        getColumnPinningClass(column)
      )}
    >
      <div className="flex items-center gap-0.5">
        {draggable && (
          <button
            type="button"
            ref={setActivatorNodeRef}
            aria-label={table.cnTable.localization.reorderColumn}
            // dnd-kit injects an aria-describedby id that can differ between the
            // server and client render; suppress that benign attribute mismatch.
            suppressHydrationWarning
            className="-ml-1 flex cursor-grab items-center text-muted-foreground opacity-70 transition-opacity outline-none group-hover/th:opacity-100 focus-visible:opacity-100 active:cursor-grabbing"
            {...attributes}
            {...listeners}
          >
            <table.cnTable.icons.dragHandle className="size-3.5" />
          </button>
        )}
        <div className="min-w-0 flex-1">{children}</div>
      </div>
      {resizable && <ColumnResizeHandle header={header} table={table} />}
    </TableHead>
  )
}

/**
 * Body row. `useSortable` is always called (disabled when row ordering is off).
 * Exposes its drag-handle props through {@link RowDragContext} so the drag
 * column's handle can activate it. Applies the selected-row accent.
 */
export function DataTableBodyRow<TData extends RowData>({
  row,
  draggable,
  children,
  className,
  onClick,
  onDoubleClick,
}: {
  row: Row<TData>
  draggable: boolean
  children: React.ReactNode
  className?: string
  onClick?: React.MouseEventHandler<HTMLTableRowElement>
  onDoubleClick?: React.MouseEventHandler<HTMLTableRowElement>
}) {
  const { attributes, listeners, setNodeRef, setActivatorNodeRef, transform, transition, isDragging } =
    useSortable({ id: row.id, disabled: !draggable, data: { type: "row" } })

  const style: React.CSSProperties = {
    transform: CSS.Transform.toString(transform),
    transition,
    position: isDragging ? "relative" : undefined,
    zIndex: isDragging ? 1 : undefined,
  }

  const dragProps = React.useMemo(
    () => ({
      attributes: attributes as unknown as Record<string, unknown>,
      listeners: listeners as Record<string, unknown> | undefined,
      setActivatorNodeRef,
    }),
    [attributes, listeners, setActivatorNodeRef]
  )

  return (
    <RowDragContext.Provider value={dragProps}>
      <TableRow
        ref={setNodeRef}
        style={style}
        data-state={row.getIsSelected() ? "selected" : undefined}
        onClick={onClick}
        onDoubleClick={onDoubleClick}
        className={cn(
          "data-[state=selected]:shadow-[inset_2px_0_0_0_var(--primary)]",
          isDragging && "bg-muted",
          (onClick || onDoubleClick) && "cursor-pointer",
          className
        )}
      >
        {children}
      </TableRow>
    </RowDragContext.Provider>
  )
}

function ariaSort(
  sorted: false | "asc" | "desc"
): React.AriaAttributes["aria-sort"] {
  if (sorted === "asc") return "ascending"
  if (sorted === "desc") return "descending"
  return "none"
}

"use client"

import * as React from "react"
import type { Cell, Column, RowData } from "@tanstack/react-table"

import {
  ContextMenu,
  ContextMenuContent,
  ContextMenuTrigger,
} from "@/components/ui/context-menu"

import { ClickToCopy } from "./click-to-copy"
import { getColumnLabel } from "./data-table-column-actions"
import { DataTableEditField } from "./data-table-edit-field"
import type { DataTableInstance } from "./types"

/** A column is editable when it has an accessor and isn't opted out via meta. */
export function isColumnEditable<TData extends RowData, TValue>(
  column: Column<TData, TValue>
): boolean {
  return (
    column.accessorFn != null && column.columnDef.meta?.enableEditing !== false
  )
}

/**
 * Resolves a leaf data cell's interactive content: an inline editor when this
 * cell/row is being edited (cell/row/table modes), otherwise the value wrapped
 * with click-to-copy, click-to-edit (cell mode), and/or a cell-actions context
 * menu as configured. `fallback` is the normal rendered value.
 */
export function DataTableBodyCellContent<TData extends RowData>({
  cell,
  table,
  fallback,
}: {
  cell: Cell<TData, unknown>
  table: DataTableInstance<TData>
  fallback: React.ReactNode
}) {
  const cn = table.cnTable
  const { row, column } = cell
  const editable = cn.enableEditing && isColumnEditable(column)
  const mode = cn.editDisplayMode

  const isCellEditing =
    mode === "cell" &&
    cn.editingCell?.rowId === row.id &&
    cn.editingCell?.columnId === column.id
  const isRowEditing = mode === "row" && cn.editingRowId === row.id
  const isTableEditing = mode === "table"

  if (editable && (isCellEditing || isRowEditing || isTableEditing)) {
    const renderEditCell = column.columnDef.meta?.renderEditCell
    if (renderEditCell) {
      return renderEditCell({ cell, row, column, table })
    }
    return mode === "row" ? (
      <RowDraftEditor cell={cell} table={table} />
    ) : (
      <LocalDraftEditor
        cell={cell}
        table={table}
        exitOnCommit={mode === "cell"}
      />
    )
  }

  let node: React.ReactNode = fallback

  const copyEnabled =
    column.columnDef.meta?.enableClickToCopy ?? cn.enableClickToCopy
  if (copyEnabled) {
    node = (
      <ClickToCopy
        value={String(cell.getValue() ?? "")}
        copyLabel={cn.localization.copy}
        copiedLabel={cn.localization.copied}
      >
        {node}
      </ClickToCopy>
    )
  } else if (editable && mode === "cell") {
    node = (
      <button
        type="button"
        onClick={() =>
          cn.setEditingCell({ rowId: row.id, columnId: column.id })
        }
        className="-mx-1 w-full rounded-sm px-1 text-left transition-colors outline-none hover:bg-muted focus-visible:ring-2 focus-visible:ring-ring/40"
      >
        {node}
      </button>
    )
  }

  if (cn.renderCellActionMenuItems) {
    node = (
      <ContextMenu>
        <ContextMenuTrigger asChild>
          <span className="block">{node}</span>
        </ContextMenuTrigger>
        <ContextMenuContent>
          {cn.renderCellActionMenuItems({ cell, row, table })}
        </ContextMenuContent>
      </ContextMenu>
    )
  }

  return node
}

/** Editor bound to the shared row draft (row/modal editing). */
function RowDraftEditor<TData extends RowData>({
  cell,
  table,
}: {
  cell: Cell<TData, unknown>
  table: DataTableInstance<TData>
}) {
  const cn = table.cnTable
  const { column } = cell
  const meta = column.columnDef.meta
  const value =
    column.id in cn.rowDraft ? cn.rowDraft[column.id] : cell.getValue()
  const error = meta?.validate?.(value)
  return (
    <DataTableEditField
      value={value}
      variant={meta?.editVariant}
      options={meta?.editSelectOptions ?? meta?.options}
      error={error}
      ariaLabel={getColumnLabel(column)}
      onChange={(next) => cn.setRowDraftValue(column.id, next)}
    />
  )
}

/** Editor with local draft state (cell + table editing). */
function LocalDraftEditor<TData extends RowData>({
  cell,
  table,
  exitOnCommit,
}: {
  cell: Cell<TData, unknown>
  table: DataTableInstance<TData>
  exitOnCommit: boolean
}) {
  const cn = table.cnTable
  const { row, column } = cell
  const meta = column.columnDef.meta
  const [draft, setDraft] = React.useState<unknown>(() => cell.getValue())
  const error = meta?.validate?.(draft)

  const commit = () => {
    if (error) return
    if (draft !== cell.getValue()) {
      cn.onEditCellSave?.({ row, column, value: draft, table })
    }
    if (exitOnCommit) cn.setEditingCell(null)
  }

  const cancel = () => {
    setDraft(cell.getValue())
    if (exitOnCommit) cn.setEditingCell(null)
  }

  return (
    <DataTableEditField
      value={draft}
      variant={meta?.editVariant}
      options={meta?.editSelectOptions ?? meta?.options}
      error={error}
      ariaLabel={getColumnLabel(column)}
      autoFocus={exitOnCommit}
      onChange={setDraft}
      onCommit={commit}
      onCancel={cancel}
    />
  )
}

"use client"

import * as React from "react"

import { Input } from "@/components/ui/input"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { cn } from "@/lib/utils"

import type { DataTableFilterOption, EditVariant } from "./types"

const FIELD_CLASS =
  "h-8 rounded-sm text-xs font-normal tracking-normal normal-case"

/**
 * A controlled inline edit field (text / number / select). The parent owns the
 * draft value; this renders the input, surfaces validation errors, and wires
 * Enter (commit) / Escape (cancel) / blur (commit) for text inputs.
 */
export function DataTableEditField({
  value,
  onChange,
  onCommit,
  onCancel,
  variant = "text",
  options,
  error,
  ariaLabel,
  autoFocus,
}: {
  value: unknown
  onChange: (value: unknown) => void
  onCommit?: () => void
  onCancel?: () => void
  variant?: EditVariant
  options?: DataTableFilterOption[]
  error?: string
  ariaLabel: string
  autoFocus?: boolean
}) {
  if (variant === "select") {
    return (
      <div className="flex flex-col gap-0.5">
        <Select
          value={value == null ? undefined : String(value)}
          onValueChange={(next) => {
            onChange(next)
            onCommit?.()
          }}
        >
          <SelectTrigger
            size="sm"
            className={cn(FIELD_CLASS, "w-full px-2")}
            aria-label={ariaLabel}
            aria-invalid={!!error}
          >
            <SelectValue placeholder="—" />
          </SelectTrigger>
          <SelectContent>
            {(options ?? []).map((option) => (
              <SelectItem key={option.value} value={option.value}>
                {option.label}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
        {error && <FieldError>{error}</FieldError>}
      </div>
    )
  }

  return (
    <div className="flex flex-col gap-0.5">
      <Input
        autoFocus={autoFocus}
        type={variant === "number" ? "number" : "text"}
        inputMode={variant === "number" ? "decimal" : undefined}
        value={value == null ? "" : String(value)}
        aria-label={ariaLabel}
        aria-invalid={!!error}
        onChange={(e) =>
          onChange(
            variant === "number"
              ? e.target.value === ""
                ? ""
                : Number(e.target.value)
              : e.target.value
          )
        }
        onKeyDown={(e) => {
          if (e.key === "Enter") {
            e.preventDefault()
            onCommit?.()
          } else if (e.key === "Escape") {
            e.preventDefault()
            onCancel?.()
          }
        }}
        onBlur={() => onCommit?.()}
        className={FIELD_CLASS}
      />
      {error && <FieldError>{error}</FieldError>}
    </div>
  )
}

function FieldError({ children }: { children: React.ReactNode }) {
  return <span className="text-[10px] text-destructive">{children}</span>
}

"use client"

import type { RowData } from "@tanstack/react-table"

import { Button } from "@/components/ui/button"
import {
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog"
import { Label } from "@/components/ui/label"

import { getColumnLabel } from "./data-table-column-actions"
import { DataTableEditField } from "./data-table-edit-field"
import { isColumnEditable } from "./data-table-edit-cell"
import type { DataTableInstance } from "./types"

/**
 * Edit/create dialog for `editDisplayMode: "modal"` (and the create form in any
 * mode). Renders an editor per editable column bound to the shared row draft;
 * Save commits via `onSaveRow` / `onCreateRow`.
 */
export function DataTableEditModal<TData extends RowData>({
  table,
}: {
  table: DataTableInstance<TData>
}) {
  const {
    localization,
    editDisplayMode,
    editingRowId,
    isCreating,
    rowDraft,
    setRowDraftValue,
    cancelEdit,
    onSaveRow,
    onCreateRow,
  } = table.cnTable

  const editingRow =
    editingRowId != null ? table.getRow(editingRowId) : undefined
  const open =
    isCreating || (editDisplayMode === "modal" && editingRowId != null)
  if (!open) return null

  const editableColumns = table
    .getAllLeafColumns()
    .filter((column) => isColumnEditable(column))

  const hasErrors = editableColumns.some((column) => {
    const value =
      column.id in rowDraft
        ? rowDraft[column.id]
        : editingRow?.getValue(column.id)
    return column.columnDef.meta?.validate?.(value) != null
  })

  const submit = () => {
    if (hasErrors) return
    if (isCreating) {
      onCreateRow?.({ values: rowDraft, table, exit: cancelEdit })
    } else if (editingRow) {
      onSaveRow?.({ row: editingRow, values: rowDraft, table, exit: cancelEdit })
    }
  }

  return (
    <Dialog open onOpenChange={(next) => !next && cancelEdit()}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle>
            {isCreating ? localization.createNewRow : localization.editRow}
          </DialogTitle>
        </DialogHeader>
        <div className="flex flex-col gap-3 py-2">
          {editableColumns.map((column) => {
            const meta = column.columnDef.meta
            const value =
              column.id in rowDraft
                ? rowDraft[column.id]
                : editingRow?.getValue(column.id)
            return (
              <div key={column.id} className="flex flex-col gap-1.5">
                <Label className="text-xs">{getColumnLabel(column)}</Label>
                <DataTableEditField
                  value={value}
                  variant={meta?.editVariant}
                  options={meta?.editSelectOptions ?? meta?.options}
                  error={meta?.validate?.(value)}
                  ariaLabel={getColumnLabel(column)}
                  onChange={(next) => setRowDraftValue(column.id, next)}
                />
              </div>
            )
          })}
        </div>
        <DialogFooter>
          <Button variant="outline" size="sm" onClick={cancelEdit}>
            {localization.cancel}
          </Button>
          <Button size="sm" onClick={submit} disabled={hasErrors}>
            {localization.save}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  )
}

"use client"

import type { Column, RowData } from "@tanstack/react-table"

import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuLabel,
  DropdownMenuRadioGroup,
  DropdownMenuRadioItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip"
import { cn } from "@/lib/utils"

import {
  defaultModeForVariant,
  modeOptionsForVariant,
  type FilterMode,
} from "./filter-fns"
import type { DataTableInstance } from "./types"

/** Effective filter mode for a column: explicit selection → meta → variant default. */
export function getEffectiveMode<TData extends RowData, TValue>(
  column: Column<TData, TValue>,
  table: DataTableInstance<TData>
): FilterMode {
  const variant = column.columnDef.meta?.variant ?? "text"
  return (
    table.cnTable.columnFilterModes[column.id] ??
    column.columnDef.meta?.filterMode ??
    defaultModeForVariant(variant)
  )
}

/**
 * The `Filter` adornment that opens a mode menu (contains/equals/…; numeric and
 * date variants get their own sets). Swapping the mode changes the column's
 * `filterFn` and resets the stale value. Hidden when the variant has a single
 * fixed mode or modes are disabled.
 */
export function DataTableFilterModeMenu<TData extends RowData, TValue>({
  column,
  table,
}: {
  column: Column<TData, TValue>
  table: DataTableInstance<TData>
}) {
  const {
    localization,
    icons,
    setColumnFilterMode,
    enableColumnFilterModes,
    renderColumnFilterModeMenuItems,
  } = table.cnTable
  const variant = column.columnDef.meta?.variant ?? "text"
  const perColumn = column.columnDef.meta?.enableColumnFilterModes
  const enabled = perColumn ?? enableColumnFilterModes
  // Restrict (and order) to the column's allowed subset when provided.
  const allowed = column.columnDef.meta?.columnFilterModeOptions
  const variantModes = modeOptionsForVariant(variant)
  const modes = allowed
    ? allowed.filter((mode) => variantModes.includes(mode))
    : variantModes

  if (!enabled || modes.length === 0) return null

  const current = getEffectiveMode(column, table)

  return (
    <DropdownMenu>
      <Tooltip>
        <TooltipTrigger asChild>
          <DropdownMenuTrigger asChild>
            <button
              type="button"
              aria-label={localization.changeFilterMode}
              className={cn(
                "flex size-8 shrink-0 items-center justify-center rounded-sm text-muted-foreground transition-colors outline-none hover:text-foreground focus-visible:ring-2 focus-visible:ring-ring/40 aria-expanded:text-foreground"
              )}
            >
              <icons.filter className="size-3.5" />
            </button>
          </DropdownMenuTrigger>
        </TooltipTrigger>
        <TooltipContent>{localization.filterMode}</TooltipContent>
      </Tooltip>
      <DropdownMenuContent align="start" className="w-52">
        <DropdownMenuLabel>{localization.filterMode}</DropdownMenuLabel>
        <DropdownMenuSeparator />
        {renderColumnFilterModeMenuItems ? (
          renderColumnFilterModeMenuItems({
            column: column as Column<TData, unknown>,
            modes,
            currentMode: current,
            onSelect: (mode) => setColumnFilterMode(column.id, mode),
            table,
          })
        ) : (
          <DropdownMenuRadioGroup
            value={current}
            onValueChange={(value) =>
              setColumnFilterMode(column.id, value as FilterMode)
            }
          >
            {modes.map((mode) => (
              <DropdownMenuRadioItem key={mode} value={mode}>
                {localization.filterModes[mode] ?? mode}
              </DropdownMenuRadioItem>
            ))}
          </DropdownMenuRadioGroup>
        )}
      </DropdownMenuContent>
    </DropdownMenu>
  )
}

"use client"

import * as React from "react"
import type { Column, RowData } from "@tanstack/react-table"
import { format } from "date-fns"

import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Calendar } from "@/components/ui/calendar"
import { Checkbox } from "@/components/ui/checkbox"
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
} from "@/components/ui/command"
import { Input } from "@/components/ui/input"
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Slider } from "@/components/ui/slider"
import { cn } from "@/lib/utils"

import { getColumnLabel } from "./data-table-column-actions"
import { getEffectiveMode } from "./data-table-filter-mode-menu"
import { VALUELESS_MODES } from "./filter-fns"
import type { IconComponent } from "./icons"
import type { DataTableFilterOption, DataTableInstance } from "./types"

export interface FilterFieldProps<TData extends RowData, TValue> {
  column: Column<TData, TValue>
  table: DataTableInstance<TData>
}

const FIELD_CLASS =
  "h-8 rounded-sm text-xs font-normal tracking-normal normal-case"

const BETWEEN_MODES = new Set(["between", "betweenInclusive"])

/**
 * Shared Calendar props so the month/year dropdowns are usable regardless of
 * which base Calendar component the consumer ships. The year dropdown derives
 * its options from the startMonth/endMonth range.
 */
const CALENDAR_NAV_PROPS = {
  captionLayout: "dropdown",
  startMonth: new Date(new Date().getFullYear() - 100, 0),
  endMonth: new Date(new Date().getFullYear() + 10, 11),
} as const

/** A muted pill shown for valueless modes (empty / not empty). */
function ValuelessLabel({ label }: { label: string }) {
  return (
    <div className="flex h-8 items-center rounded-sm border border-dashed px-2 text-xs text-muted-foreground">
      {label}
    </div>
  )
}

/** Options for select-style variants: explicit `meta.options` or faceted values. */
function useSelectOptions<TData extends RowData, TValue>(
  column: Column<TData, TValue>
): { options: DataTableFilterOption[]; counts: Map<string, number> } {
  const facets = column.getFacetedUniqueValues()
  return React.useMemo(() => {
    const counts = new Map<string, number>()
    for (const [value, count] of facets) {
      if (value == null) continue
      counts.set(String(value), count)
    }
    const explicit = column.columnDef.meta?.options
    if (explicit && explicit.length > 0) {
      return { options: explicit, counts }
    }
    const options = Array.from(counts.keys())
      .sort((a, b) => a.localeCompare(b))
      .map((value) => ({ label: value, value }))
    return { options, counts }
  }, [facets, column.columnDef.meta?.options])
}

export function TextFilterField<TData extends RowData, TValue>({
  column,
  table,
}: FilterFieldProps<TData, TValue>) {
  const { localization, icons } = table.cnTable
  const mode = getEffectiveMode(column, table)
  if (VALUELESS_MODES.has(mode)) {
    return <ValuelessLabel label={localization.filterModes[mode] ?? mode} />
  }
  const value = (column.getFilterValue() ?? "") as string
  return (
    <ClearableInput
      value={value}
      onChange={(next) => column.setFilterValue(next || undefined)}
      placeholder={localization.filterPlaceholder(getColumnLabel(column))}
      ariaLabel={localization.filterByColumn(getColumnLabel(column))}
      clearLabel={localization.clearFilter}
      ClearIcon={icons.clear}
    />
  )
}

export function NumberFilterField<TData extends RowData, TValue>({
  column,
  table,
}: FilterFieldProps<TData, TValue>) {
  const { localization } = table.cnTable
  const mode = getEffectiveMode(column, table)

  if (VALUELESS_MODES.has(mode)) {
    return <ValuelessLabel label={localization.filterModes[mode] ?? mode} />
  }

  if (BETWEEN_MODES.has(mode)) {
    const value = (column.getFilterValue() ?? ["", ""]) as [
      string | number,
      string | number,
    ]
    const setBound = (index: 0 | 1, next: string) => {
      const draft: [string | number, string | number] = [
        value[0] ?? "",
        value[1] ?? "",
      ]
      draft[index] = next
      column.setFilterValue(
        draft[0] === "" && draft[1] === "" ? undefined : draft
      )
    }
    return (
      <div className="flex items-center gap-1">
        <Input
          type="number"
          inputMode="decimal"
          value={String(value[0] ?? "")}
          onChange={(e) => setBound(0, e.target.value)}
          placeholder={localization.min}
          aria-label={localization.min}
          className={FIELD_CLASS}
        />
        <span className="text-muted-foreground">–</span>
        <Input
          type="number"
          inputMode="decimal"
          value={String(value[1] ?? "")}
          onChange={(e) => setBound(1, e.target.value)}
          placeholder={localization.max}
          aria-label={localization.max}
          className={FIELD_CLASS}
        />
      </div>
    )
  }

  const value = (column.getFilterValue() ?? "") as string
  return (
    <Input
      type="number"
      inputMode="decimal"
      value={value}
      onChange={(e) => column.setFilterValue(e.target.value || undefined)}
      placeholder={localization.filterPlaceholder(getColumnLabel(column))}
      aria-label={localization.filterByColumn(getColumnLabel(column))}
      className={FIELD_CLASS}
    />
  )
}

export function RangeSliderFilterField<TData extends RowData, TValue>({
  column,
}: FilterFieldProps<TData, TValue>) {
  const facetedMinMax = column.getFacetedMinMaxValues()
  const min = Math.floor(facetedMinMax?.[0] ?? 0)
  const max = Math.ceil(facetedMinMax?.[1] ?? 100)
  const value = (column.getFilterValue() ?? [min, max]) as [number, number]
  const current: [number, number] = [
    value[0] === ("" as unknown) || value[0] == null ? min : Number(value[0]),
    value[1] === ("" as unknown) || value[1] == null ? max : Number(value[1]),
  ]
  return (
    <div className="flex flex-col gap-1.5 px-1 pt-1">
      <Slider
        min={min}
        max={max}
        step={1}
        value={current}
        onValueChange={(next) =>
          column.setFilterValue(
            next[0] === min && next[1] === max ? undefined : next
          )
        }
        aria-label={getColumnLabel(column)}
      />
      <div className="flex justify-between text-[10px] tabular-nums text-muted-foreground">
        <span>{current[0]}</span>
        <span>{current[1]}</span>
      </div>
    </div>
  )
}

export function SelectFilterField<TData extends RowData, TValue>({
  column,
  table,
}: FilterFieldProps<TData, TValue>) {
  const { localization, icons } = table.cnTable
  const { options } = useSelectOptions(column)
  const value = (column.getFilterValue() as string) || ""
  return (
    <div className="flex items-center gap-1">
      <Select
        value={value || undefined}
        onValueChange={(next) => column.setFilterValue(next || undefined)}
      >
        <SelectTrigger
          size="sm"
          className={cn(FIELD_CLASS, "flex-1 px-2")}
          aria-label={localization.filterByColumn(getColumnLabel(column))}
        >
          <SelectValue
            placeholder={localization.filterPlaceholder(getColumnLabel(column))}
          />
        </SelectTrigger>
        <SelectContent>
          {options.map((option) => (
            <SelectItem key={option.value} value={option.value}>
              {option.label}
            </SelectItem>
          ))}
        </SelectContent>
      </Select>
      {value && (
        <Button
          variant="ghost"
          size="icon"
          aria-label={localization.clearFilter}
          onClick={() => column.setFilterValue(undefined)}
          className="size-7"
        >
          <icons.clear />
        </Button>
      )}
    </div>
  )
}

export function MultiSelectFilterField<TData extends RowData, TValue>({
  column,
  table,
}: FilterFieldProps<TData, TValue>) {
  const { localization } = table.cnTable
  const { options, counts } = useSelectOptions(column)
  const selected = (column.getFilterValue() as string[]) ?? []

  const toggle = (value: string) => {
    const next = selected.includes(value)
      ? selected.filter((v) => v !== value)
      : [...selected, value]
    column.setFilterValue(next.length > 0 ? next : undefined)
  }

  return (
    <Popover>
      <PopoverTrigger asChild>
        <Button
          variant="outline"
          size="sm"
          className={cn(FIELD_CLASS, "w-full justify-between px-2 font-normal")}
          aria-label={localization.filterByColumn(getColumnLabel(column))}
        >
          {selected.length > 0 ? (
            <span className="flex items-center gap-1">
              <Badge variant="secondary" className="rounded-sm px-1">
                {selected.length}
              </Badge>
              <span className="truncate">{selected.join(", ")}</span>
            </span>
          ) : (
            <span className="text-muted-foreground">
              {localization.filterPlaceholder(getColumnLabel(column))}
            </span>
          )}
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-56 p-0" align="start">
        <Command>
          <CommandInput placeholder={localization.search} className="h-8" />
          <CommandList>
            <CommandEmpty>{localization.noRecordsToDisplay}</CommandEmpty>
            <CommandGroup>
              {options.map((option) => {
                const isSelected = selected.includes(option.value)
                return (
                  <CommandItem
                    key={option.value}
                    value={option.value}
                    onSelect={() => toggle(option.value)}
                    className="gap-2"
                  >
                    <Checkbox checked={isSelected} className="pointer-events-none" />
                    <span className="flex-1 truncate">{option.label}</span>
                    <span className="text-xs tabular-nums text-muted-foreground">
                      {counts.get(option.value) ?? 0}
                    </span>
                  </CommandItem>
                )
              })}
            </CommandGroup>
          </CommandList>
        </Command>
      </PopoverContent>
    </Popover>
  )
}

export function CheckboxFilterField<TData extends RowData, TValue>({
  column,
  table,
}: FilterFieldProps<TData, TValue>) {
  const { localization } = table.cnTable
  const value = column.getFilterValue()
  const checked = value === true
  return (
    <label className="flex h-8 items-center gap-2 text-xs text-muted-foreground">
      <Checkbox
        checked={checked}
        onCheckedChange={(next) =>
          column.setFilterValue(next === true ? true : undefined)
        }
        aria-label={localization.filterByColumn(getColumnLabel(column))}
      />
      {getColumnLabel(column)}
    </label>
  )
}

export function DateFilterField<TData extends RowData, TValue>({
  column,
  table,
}: FilterFieldProps<TData, TValue>) {
  const { localization, icons } = table.cnTable
  const mode = getEffectiveMode(column, table)

  if (VALUELESS_MODES.has(mode)) {
    return <ValuelessLabel label={localization.filterModes[mode] ?? mode} />
  }

  // The `betweenDates` mode (and the date-range variant) selects a range.
  if (mode === "betweenDates") {
    return <DateRangeFilterField column={column} table={table} />
  }

  const value = column.getFilterValue() as Date | undefined
  return (
    <Popover>
      <PopoverTrigger asChild>
        <Button
          variant="outline"
          size="sm"
          className={cn(FIELD_CLASS, "w-full justify-start gap-2 px-2 font-normal")}
          aria-label={localization.filterByColumn(getColumnLabel(column))}
        >
          <icons.calendar className="text-muted-foreground" />
          {value ? (
            format(value, "PP")
          ) : (
            <span className="text-muted-foreground">{localization.pickDate}</span>
          )}
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-auto p-0" align="start">
        <Calendar
          mode="single"
          selected={value}
          onSelect={(date) => column.setFilterValue(date ?? undefined)}
          autoFocus
          {...CALENDAR_NAV_PROPS}
        />
      </PopoverContent>
    </Popover>
  )
}

export function DateRangeFilterField<TData extends RowData, TValue>({
  column,
  table,
}: FilterFieldProps<TData, TValue>) {
  const { localization, icons } = table.cnTable
  const value = (column.getFilterValue() as [Date?, Date?]) ?? [undefined, undefined]
  const from = value[0]
  const to = value[1]
  return (
    <Popover>
      <PopoverTrigger asChild>
        <Button
          variant="outline"
          size="sm"
          className={cn(FIELD_CLASS, "w-full justify-start gap-2 px-2 font-normal")}
          aria-label={localization.filterByColumn(getColumnLabel(column))}
        >
          <icons.calendar className="text-muted-foreground" />
          {from || to ? (
            <span>
              {from ? format(from, "PP") : "…"} – {to ? format(to, "PP") : "…"}
            </span>
          ) : (
            <span className="text-muted-foreground">
              {localization.pickDateRange}
            </span>
          )}
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-auto p-0" align="start">
        <Calendar
          mode="range"
          selected={{ from, to }}
          onSelect={(range) =>
            column.setFilterValue(
              range?.from || range?.to ? [range?.from, range?.to] : undefined
            )
          }
          autoFocus
          {...CALENDAR_NAV_PROPS}
        />
      </PopoverContent>
    </Popover>
  )
}

/** A text input with a trailing clear affordance. */
function ClearableInput({
  value,
  onChange,
  placeholder,
  ariaLabel,
  clearLabel,
  ClearIcon,
}: {
  value: string
  onChange: (next: string) => void
  placeholder: string
  ariaLabel: string
  clearLabel: string
  ClearIcon: IconComponent
}) {
  return (
    <div className="relative flex-1">
      <Input
        value={value}
        onChange={(e) => onChange(e.target.value)}
        placeholder={placeholder}
        aria-label={ariaLabel}
        className={cn(FIELD_CLASS, value && "pr-7")}
      />
      {value && (
        <button
          type="button"
          aria-label={clearLabel}
          onClick={() => onChange("")}
          className="absolute inset-y-0 right-1.5 flex items-center text-muted-foreground transition-colors hover:text-foreground"
        >
          <ClearIcon className="size-3.5" />
        </button>
      )}
    </div>
  )
}

"use client"

import * as React from "react"
import type { RowData } from "@tanstack/react-table"

import { Button } from "@/components/ui/button"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuLabel,
  DropdownMenuRadioGroup,
  DropdownMenuRadioItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import { Input } from "@/components/ui/input"
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip"
import { cn } from "@/lib/utils"

import type { GlobalFilterMode } from "./filter-fns"
import type { DataTableInstance } from "./types"

const GLOBAL_MODES: GlobalFilterMode[] = [
  "fuzzy",
  "contains",
  "startsWith",
  "endsWith",
  "equals",
]

/**
 * Expandable global search (MRT order: first in the toolbar icon cluster). The
 * search button expands into an input with a leading icon, an optional
 * search-mode menu, and a clear affordance. Input is debounced in manual
 * (server) mode so each keystroke doesn't fire a request.
 */
export function DataTableGlobalFilter<TData extends RowData>({
  table,
}: {
  table: DataTableInstance<TData>
}) {
  const {
    localization,
    icons,
    enableGlobalFilter,
    enableGlobalFilterModes,
    globalFilterMode,
    setGlobalFilterMode,
    renderGlobalFilterModeMenuItems,
  } = table.cnTable

  const external = (table.getState().globalFilter ?? "") as string
  const [expanded, setExpanded] = React.useState(external.length > 0)
  const [value, setValue] = React.useState(external)
  const inputRef = React.useRef<HTMLInputElement>(null)

  const debounceMs = table.options.manualFiltering ? 300 : 0

  React.useEffect(() => {
    if (value === (table.getState().globalFilter ?? "")) return
    const id = setTimeout(
      () => table.setGlobalFilter(value || undefined),
      debounceMs
    )
    return () => clearTimeout(id)
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [value, debounceMs])

  if (!enableGlobalFilter) return null

  if (!expanded) {
    return (
      <Tooltip>
        <TooltipTrigger asChild>
          <Button
            variant="outline"
            size="icon"
            aria-label={localization.search}
            className="size-8"
            onClick={() => {
              setExpanded(true)
              requestAnimationFrame(() => inputRef.current?.focus())
            }}
          >
            <icons.search />
          </Button>
        </TooltipTrigger>
        <TooltipContent>{localization.search}</TooltipContent>
      </Tooltip>
    )
  }

  const clear = () => {
    setValue("")
    table.setGlobalFilter(undefined)
    setExpanded(false)
  }

  return (
    <div className="flex h-9 items-center gap-0.5 rounded-md border bg-background pr-1 pl-2 focus-within:border-ring">
      <icons.search className="size-3.5 shrink-0 text-muted-foreground" />
      <Input
        ref={inputRef}
        value={value}
        onChange={(e) => setValue(e.target.value)}
        onBlur={() => {
          if (!value) setExpanded(false)
        }}
        placeholder={localization.searchPlaceholder}
        aria-label={localization.search}
        className={cn(
          "h-7 w-40 border-0 px-1 text-xs font-normal tracking-normal normal-case shadow-none focus-visible:ring-0 sm:w-56"
        )}
      />
      {value && (
        <Button
          variant="ghost"
          size="icon"
          aria-label={localization.clearSearch}
          onClick={clear}
          className="size-7"
        >
          <icons.clear />
        </Button>
      )}
      {enableGlobalFilterModes && (
        <DropdownMenu>
          <Tooltip>
            <TooltipTrigger asChild>
              <DropdownMenuTrigger asChild>
                <Button
                  variant="ghost"
                  size="icon"
                  aria-label={localization.globalFilterMode}
                  className="size-7"
                >
                  <icons.search className="size-3" />
                </Button>
              </DropdownMenuTrigger>
            </TooltipTrigger>
            <TooltipContent>{localization.globalFilterMode}</TooltipContent>
          </Tooltip>
          <DropdownMenuContent align="end" className="w-48">
            <DropdownMenuLabel>
              {localization.globalFilterMode}
            </DropdownMenuLabel>
            <DropdownMenuSeparator />
            {renderGlobalFilterModeMenuItems ? (
              renderGlobalFilterModeMenuItems({
                modes: GLOBAL_MODES,
                currentMode: globalFilterMode,
                onSelect: setGlobalFilterMode,
                table,
              })
            ) : (
              <DropdownMenuRadioGroup
                value={globalFilterMode}
                onValueChange={(mode) =>
                  setGlobalFilterMode(mode as GlobalFilterMode)
                }
              >
                {GLOBAL_MODES.map((mode) => (
                  <DropdownMenuRadioItem key={mode} value={mode}>
                    {localization.filterModes[mode] ?? mode}
                  </DropdownMenuRadioItem>
                ))}
              </DropdownMenuRadioGroup>
            )}
          </DropdownMenuContent>
        </DropdownMenu>
      )}
    </div>
  )
}

"use client"

import type { RowData } from "@tanstack/react-table"
import { useDroppable } from "@dnd-kit/core"

import { Badge } from "@/components/ui/badge"
import { cn } from "@/lib/utils"

import { getColumnLabel } from "./data-table-column-actions"
import type { DataTableInstance } from "./types"

export const GROUP_DROPZONE_ID = "cn-group-dropzone"

/**
 * The MRT "drop to group by" zone: a dashed strip below the toolbar showing
 * chips for the active grouping columns (each removable) and acting as a drop
 * target for column drags (handled by the column DnD context in `<DataTable>`).
 */
export function DataTableDropToGroupZone<TData extends RowData>({
  table,
}: {
  table: DataTableInstance<TData>
}) {
  const { localization, icons } = table.cnTable
  const grouping = table.getState().grouping
  const { setNodeRef, isOver } = useDroppable({ id: GROUP_DROPZONE_ID })

  return (
    <div
      ref={setNodeRef}
      className={cn(
        "flex min-h-10 flex-wrap items-center gap-2 rounded-md border border-dashed px-3 py-2 text-xs text-muted-foreground transition-colors",
        isOver && "border-primary bg-muted text-foreground"
      )}
    >
      <icons.group className="size-3.5 shrink-0" />
      {grouping.length === 0 ? (
        <span>{localization.dropToGroupBy}</span>
      ) : (
        grouping.map((columnId) => {
          const column = table.getColumn(columnId)
          if (!column) return null
          return (
            <Badge
              key={columnId}
              variant="secondary"
              className="gap-1 rounded-sm pr-1 normal-case"
            >
              {getColumnLabel(column)}
              <button
                type="button"
                aria-label={localization.ungroupByColumn(
                  getColumnLabel(column)
                )}
                onClick={() => column.toggleGrouping()}
                className="rounded-sm text-muted-foreground transition-colors hover:text-foreground"
              >
                <icons.clear className="size-3" />
              </button>
            </Badge>
          )
        })
      )}
    </div>
  )
}

"use client"

import type * as React from "react"
import type { RowData } from "@tanstack/react-table"

import { Button } from "@/components/ui/button"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip"

import type { DataTableInstance } from "./types"

interface DataTablePaginationProps<TData extends RowData> {
  table: DataTableInstance<TData>
  pageSizeOptions?: number[]
}

/**
 * Bottom toolbar. Left: rows-per-page select. Right: MRT-style "start–end of
 * total" range label + first/prev/next/last icon buttons. Works in client and
 * manual/server pagination (counts come from the table instance).
 */
export function DataTablePagination<TData extends RowData>({
  table,
  pageSizeOptions = [5, 10, 25, 50, 100],
}: DataTablePaginationProps<TData>) {
  const { localization, icons } = table.cnTable
  const { pageIndex, pageSize } = table.getState().pagination

  const totalRows = table.getRowCount()
  const start = totalRows === 0 ? 0 : pageIndex * pageSize + 1
  const end = Math.min((pageIndex + 1) * pageSize, totalRows)

  return (
    <div
      data-slot="data-table-pagination"
      className="flex flex-wrap items-center justify-between gap-4 py-1"
    >
      <div className="flex items-center gap-2">
        <span className="text-xs font-medium tracking-wide text-muted-foreground">
          {localization.rowsPerPage}
        </span>
        <Select
          value={`${pageSize}`}
          onValueChange={(value) => table.setPageSize(Number(value))}
        >
          <SelectTrigger
            size="sm"
            className="h-8 w-[4.5rem]"
            aria-label={localization.rowsPerPage}
          >
            <SelectValue placeholder={`${pageSize}`} />
          </SelectTrigger>
          <SelectContent>
            {pageSizeOptions.map((size) => (
              <SelectItem key={size} value={`${size}`}>
                {size}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </div>

      <div className="flex items-center gap-3">
        <span className="text-xs font-medium tracking-wide text-muted-foreground tabular-nums">
          {localization.paginationRange(start, end, totalRows)}
        </span>
        <div className="flex items-center gap-1">
          <PaginationButton
            label={localization.goToFirstPage}
            onClick={() => table.setPageIndex(0)}
            disabled={!table.getCanPreviousPage()}
          >
            <icons.pageFirst />
          </PaginationButton>
          <PaginationButton
            label={localization.goToPreviousPage}
            onClick={() => table.previousPage()}
            disabled={!table.getCanPreviousPage()}
          >
            <icons.pagePrev />
          </PaginationButton>
          <PaginationButton
            label={localization.goToNextPage}
            onClick={() => table.nextPage()}
            disabled={!table.getCanNextPage()}
          >
            <icons.pageNext />
          </PaginationButton>
          <PaginationButton
            label={localization.goToLastPage}
            onClick={() => table.setPageIndex(table.getPageCount() - 1)}
            disabled={!table.getCanNextPage()}
          >
            <icons.pageLast />
          </PaginationButton>
        </div>
      </div>
    </div>
  )
}

function PaginationButton({
  label,
  onClick,
  disabled,
  children,
}: {
  label: string
  onClick: () => void
  disabled: boolean
  children: React.ReactNode
}) {
  return (
    <Tooltip>
      <TooltipTrigger asChild>
        <Button
          variant="outline"
          size="icon"
          aria-label={label}
          onClick={onClick}
          disabled={disabled}
          className="size-8"
        >
          {children}
        </Button>
      </TooltipTrigger>
      <TooltipContent>{label}</TooltipContent>
    </Tooltip>
  )
}

"use client"

import type { ColumnDef, Row, RowData } from "@tanstack/react-table"

import { Button } from "@/components/ui/button"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"

import type { DataTableInstance } from "./types"

export const ROW_ACTIONS_COLUMN_ID = "cn-row-actions"

/** Trailing actions column: edit/save/cancel controls + the consumer's
 *  `renderRowActions` slot. */
export function createRowActionsColumn<
  TData extends RowData,
>(): ColumnDef<TData> {
  return {
    id: ROW_ACTIONS_COLUMN_ID,
    enableSorting: false,
    enableHiding: false,
    enableColumnFilter: false,
    enableResizing: false,
    enableGrouping: false,
    size: 90,
    minSize: 80,
    meta: { disableColumnActions: true, align: "right" },
    header: () => null,
    cell: ({ row, table }) => (
      <RowActionsCell row={row} table={table as DataTableInstance<TData>} />
    ),
  }
}

function RowActionsCell<TData extends RowData>({
  row,
  table,
}: {
  row: Row<TData>
  table: DataTableInstance<TData>
}) {
  const {
    localization,
    icons,
    enableEditing,
    editDisplayMode,
    editingRowId,
    rowDraft,
    onSaveRow,
    beginRowEdit,
    cancelEdit,
    renderRowActions,
    renderRowActionMenuItems,
  } = table.cnTable

  const isEditingThisRow = editDisplayMode === "row" && editingRowId === row.id

  if (isEditingThisRow) {
    return (
      <div className="flex items-center justify-end gap-1">
        <Button
          variant="ghost"
          size="icon"
          aria-label={localization.save}
          className="size-7"
          onClick={() =>
            onSaveRow?.({ row, values: rowDraft, table, exit: cancelEdit })
          }
        >
          <icons.save />
        </Button>
        <Button
          variant="ghost"
          size="icon"
          aria-label={localization.cancel}
          className="size-7"
          onClick={cancelEdit}
        >
          <icons.cancel />
        </Button>
      </div>
    )
  }

  const canInlineEdit =
    enableEditing && (editDisplayMode === "row" || editDisplayMode === "modal")

  return (
    <div className="flex items-center justify-end gap-1">
      {canInlineEdit && (
        <Button
          variant="ghost"
          size="icon"
          aria-label={localization.edit}
          className="size-7"
          onClick={() => beginRowEdit(row)}
        >
          <icons.edit />
        </Button>
      )}
      {renderRowActions?.({ row, table })}
      {renderRowActionMenuItems && (
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button
              variant="ghost"
              size="icon"
              aria-label={localization.rowActions}
              className="size-7"
            >
              <icons.columnActions />
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="end">
            {renderRowActionMenuItems({ row, table })}
          </DropdownMenuContent>
        </DropdownMenu>
      )}
    </div>
  )
}

"use client"

import type { RowData } from "@tanstack/react-table"

import { Button } from "@/components/ui/button"
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip"
import { cn } from "@/lib/utils"

import { DENSITY_ORDER } from "./types"
import type { DataTableInstance } from "./types"

/** Funnel toggle that shows/hides the filter row. */
export function DataTableFilterToggle<TData extends RowData>({
  table,
}: {
  table: DataTableInstance<TData>
}) {
  const { localization, icons, showColumnFilters, setShowColumnFilters } =
    table.cnTable
  const label = showColumnFilters
    ? localization.hideColumnFilters
    : localization.showColumnFilters
  return (
    <Tooltip>
      <TooltipTrigger asChild>
        <Button
          variant="outline"
          size="icon"
          aria-label={label}
          aria-pressed={showColumnFilters}
          onClick={() => setShowColumnFilters((prev) => !prev)}
          className={cn("size-8", showColumnFilters && "bg-muted text-foreground")}
        >
          <icons.filter />
        </Button>
      </TooltipTrigger>
      <TooltipContent>{label}</TooltipContent>
    </Tooltip>
  )
}

const DENSITY_LABEL_KEYS = {
  comfortable: "densityComfortable",
  compact: "densityCompact",
  spacious: "densitySpacious",
} as const

/** Single button that cycles comfortable → compact → spacious. */
export function DataTableDensityToggle<TData extends RowData>({
  table,
}: {
  table: DataTableInstance<TData>
}) {
  const { localization, icons, density, setDensity } = table.cnTable
  const currentLabel = localization[DENSITY_LABEL_KEYS[density]]
  const label = `${localization.toggleDensity} (${currentLabel})`
  return (
    <Tooltip>
      <TooltipTrigger asChild>
        <Button
          variant="outline"
          size="icon"
          aria-label={label}
          className="size-8"
          onClick={() =>
            setDensity((prev) => {
              const next =
                DENSITY_ORDER[
                  (DENSITY_ORDER.indexOf(prev) + 1) % DENSITY_ORDER.length
                ]
              return next ?? "comfortable"
            })
          }
        >
          <icons.density />
        </Button>
      </TooltipTrigger>
      <TooltipContent>{label}</TooltipContent>
    </Tooltip>
  )
}

/** Full-screen toggle (state-driven; the surface fixes itself to the viewport). */
export function DataTableFullscreenToggle<TData extends RowData>({
  table,
}: {
  table: DataTableInstance<TData>
}) {
  const { localization, icons, isFullscreen, setIsFullscreen } = table.cnTable
  const label = isFullscreen
    ? localization.exitFullscreen
    : localization.enterFullscreen
  return (
    <Tooltip>
      <TooltipTrigger asChild>
        <Button
          variant="outline"
          size="icon"
          aria-label={label}
          aria-pressed={isFullscreen}
          onClick={() => setIsFullscreen((prev) => !prev)}
          className="size-8"
        >
          {isFullscreen ? <icons.fullscreenExit /> : <icons.fullscreenEnter />}
        </Button>
      </TooltipTrigger>
      <TooltipContent>{label}</TooltipContent>
    </Tooltip>
  )
}

"use client"

import type { RowData } from "@tanstack/react-table"

import { cn } from "@/lib/utils"

import { DataTableExportMenu } from "./data-table-export-menu"
import { DataTableGlobalFilter } from "./data-table-global-filter"
import {
  DataTableDensityToggle,
  DataTableFilterToggle,
  DataTableFullscreenToggle,
} from "./data-table-toolbar-controls"
import { DataTableViewOptions } from "./data-table-view-options"
import type { DataTableInstance } from "./types"

/**
 * Top toolbar. Left region: title slot + consumer toolbar actions. Right
 * region: the MRT-ordered icon cluster (global search → filters funnel →
 * column visibility → density → full screen).
 */
export function DataTableToolbar<TData extends RowData>({
  table,
}: {
  table: DataTableInstance<TData>
}) {
  const {
    title,
    renderToolbarActions,
    renderToolbarInternalActions,
    enableToolbarInternalActions,
    enableGlobalFilter,
    positionGlobalFilter,
    enableColumnFilters,
    enableColumnActions,
    enableExport,
    enableDensityToggle,
    enableFullscreenToggle,
    exportFileName,
  } = table.cnTable

  const anyFilterable = table
    .getAllColumns()
    .some((column) => column.getCanFilter())

  const showGlobalFilter = enableGlobalFilter && positionGlobalFilter !== "none"

  return (
    <div
      data-slot="data-table-toolbar"
      className="flex items-start justify-between gap-3 py-1"
    >
      <div className="flex min-h-9 flex-1 flex-wrap items-center gap-2">
        {showGlobalFilter && positionGlobalFilter === "left" && (
          <DataTableGlobalFilter table={table} />
        )}
        {title != null && (
          <div className="text-sm font-semibold tracking-wide">{title}</div>
        )}
        {renderToolbarActions?.({ table })}
      </div>

      {enableToolbarInternalActions && (
        <div
          data-slot="data-table-toolbar-actions"
          className="flex shrink-0 items-center gap-1.5"
        >
          {renderToolbarInternalActions ? (
            renderToolbarInternalActions({ table })
          ) : (
            <>
              {showGlobalFilter && positionGlobalFilter === "right" && (
                <DataTableGlobalFilter table={table} />
              )}
              {enableColumnFilters && anyFilterable && (
                <DataTableFilterToggle table={table} />
              )}
              {enableColumnActions && <DataTableViewOptions table={table} />}
              {enableExport && (
                <DataTableExportMenu table={table} fileName={exportFileName} />
              )}
              {enableDensityToggle && <DataTableDensityToggle table={table} />}
              {enableFullscreenToggle && (
                <DataTableFullscreenToggle table={table} />
              )}
            </>
          )}
        </div>
      )}
    </div>
  )
}

/**
 * Selection alert banner shown between the toolbar and the table when any rows
 * are selected: a muted strip with the localized count and a Clear action.
 */
export function DataTableAlertBanner<TData extends RowData>({
  table,
}: {
  table: DataTableInstance<TData>
}) {
  const { localization, enableRowSelection } = table.cnTable
  if (!enableRowSelection) return null

  const selectedCount = table.getSelectedRowModel().rows.length
  if (selectedCount === 0) return null

  const totalCount = table.getPrePaginationRowModel().rows.length

  return (
    <div
      data-slot="data-table-alert-banner"
      className={cn(
        "flex items-center justify-between gap-3 rounded-md border bg-muted px-3 py-2 text-xs font-medium text-muted-foreground"
      )}
      role="status"
    >
      <span>{localization.rowsSelected(selectedCount, totalCount)}</span>
      <button
        type="button"
        onClick={() => table.resetRowSelection()}
        className="font-semibold tracking-wide text-foreground underline-offset-4 hover:underline"
      >
        {localization.clearSelection}
      </button>
    </div>
  )
}

"use client"

import type { RowData } from "@tanstack/react-table"

import { Button } from "@/components/ui/button"
import {
  DropdownMenu,
  DropdownMenuCheckboxItem,
  DropdownMenuContent,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip"

import { getColumnLabel } from "./data-table-column-actions"
import type { DataTableInstance } from "./types"

/**
 * Column visibility menu (toolbar icon cluster). Lists every hideable column
 * as a checkbox item; the header `label`/string is used for the menu text.
 */
export function DataTableViewOptions<TData extends RowData>({
  table,
}: {
  table: DataTableInstance<TData>
}) {
  const { localization, icons } = table.cnTable
  const hideableColumns = table
    .getAllColumns()
    .filter((column) => column.getCanHide())

  if (hideableColumns.length === 0) return null

  return (
    <DropdownMenu>
      <Tooltip>
        <TooltipTrigger asChild>
          <DropdownMenuTrigger asChild>
            <Button
              variant="outline"
              size="icon"
              aria-label={localization.columnVisibility}
              className="size-8"
            >
              <icons.columnVisibility />
            </Button>
          </DropdownMenuTrigger>
        </TooltipTrigger>
        <TooltipContent>{localization.columnVisibility}</TooltipContent>
      </Tooltip>
      <DropdownMenuContent align="end" className="w-52">
        <DropdownMenuLabel>{localization.columnVisibility}</DropdownMenuLabel>
        <DropdownMenuSeparator />
        {hideableColumns.map((column) => (
          <DropdownMenuCheckboxItem
            key={column.id}
            className="capitalize"
            checked={column.getIsVisible()}
            onCheckedChange={(value) => column.toggleVisibility(!!value)}
            onSelect={(e) => e.preventDefault()}
          >
            {getColumnLabel(column)}
          </DropdownMenuCheckboxItem>
        ))}
      </DropdownMenuContent>
    </DropdownMenu>
  )
}

"use client"

import * as React from "react"
import {
  flexRender,
  type Cell,
  type Column,
  type Header,
  type Row,
  type RowData,
} from "@tanstack/react-table"
import {
  DndContext,
  KeyboardSensor,
  PointerSensor,
  closestCenter,
  useSensor,
  useSensors,
  type DragEndEvent,
} from "@dnd-kit/core"
import {
  SortableContext,
  arrayMove,
  horizontalListSortingStrategy,
  sortableKeyboardCoordinates,
  verticalListSortingStrategy,
} from "@dnd-kit/sortable"
import { useVirtualizer } from "@tanstack/react-virtual"

import {
  Table,
  TableBody,
  TableCaption,
  TableCell,
  TableFooter,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table"
import { Skeleton } from "@/components/ui/skeleton"
import { TooltipProvider } from "@/components/ui/tooltip"
import { cn } from "@/lib/utils"

import {
  getColumnPinningClass,
  getColumnPinningStyle,
  getColumnSizeVars,
  getColumnWidthStyle,
} from "./column-styles"
import { DataTableColumnFilter } from "./data-table-column-filter"
import { DataTableColumnHeader } from "./data-table-column-header"
import { DataTableBodyRow, DataTableHeadCell } from "./data-table-dnd"
import { DataTableBodyCellContent } from "./data-table-edit-cell"
import { DataTableEditModal } from "./data-table-edit-modal"
import { getEffectiveMode } from "./data-table-filter-mode-menu"
import {
  DataTableDropToGroupZone,
  GROUP_DROPZONE_ID,
} from "./data-table-grouping"
import { DataTablePagination } from "./data-table-pagination"
import { DataTableAlertBanner, DataTableToolbar } from "./data-table-toolbar"
import {
  EXPAND_COLUMN_ID,
  ROW_DRAG_COLUMN_ID,
  ROW_NUMBER_COLUMN_ID,
} from "./display-columns"
import { ROW_ACTIONS_COLUMN_ID } from "./data-table-row-actions"
import { SUBSTRING_MODES } from "./filter-fns"
import { Highlight } from "./highlight"
import { SELECTION_COLUMN_ID } from "./selection-column"
import { DENSITY_CELL_PADDING, type DataTableInstance } from "./types"
import { useGridNavigation } from "./use-grid-navigation"

interface DataTableProps<
  TData extends RowData,
> extends React.ComponentProps<"div"> {
  table: DataTableInstance<TData>
  /** Page-size options for the bottom pagination control. */
  pageSizeOptions?: number[]
  /** Extra classes for the scrollable table surface (e.g. a max-height to
   *  engage the sticky header/footer or to bound a virtualized list). */
  surfaceClassName?: string
}

const ALIGN_CELL = {
  left: "text-left",
  center: "text-center",
  right: "text-right",
} as const

const DISPLAY_COLUMN_IDS = new Set([
  SELECTION_COLUMN_ID,
  ROW_NUMBER_COLUMN_ID,
  ROW_DRAG_COLUMN_ID,
])

// All injected (non-user) columns, used to find the first real data column so
// tree (sub-row) rows can be indented by depth there.
const NON_DATA_COLUMN_IDS = new Set([
  SELECTION_COLUMN_ID,
  ROW_NUMBER_COLUMN_ID,
  ROW_DRAG_COLUMN_ID,
  EXPAND_COLUMN_ID,
  ROW_ACTIONS_COLUMN_ID,
])

/**
 * Renders a data table from an instance produced by {@link useDataTable}.
 * Vertical stack: top toolbar → alert banner → drop-to-group zone → bordered
 * surface (sticky header, optional filter row, body, optional sticky footer) →
 * pagination. Wires DnD column/row ordering, pinning, resizing, grouping,
 * expansion, and detail panels.
 */
export function DataTable<TData extends RowData>({
  table,
  pageSizeOptions,
  surfaceClassName,
  className,
  ...props
}: DataTableProps<TData>) {
  const {
    density,
    isFullscreen,
    showProgressBars,
    showSkeletons,
    showLoadingOverlay,
    showColumnFilters,
    enableColumnFilters,
    enableFilterMatchHighlighting,
    columnsWithCustomCell,
    enableColumnOrdering,
    enableColumnResizing,
    enableRowOrdering,
    enableGrouping,
    enableStickyFooter,
    renderDetailPanel,
    enableRowVirtualization,
    enableColumnVirtualization,
    rowVirtualizerOptions,
    columnVirtualizerOptions,
    rowVirtualizerInstanceRef,
    columnVirtualizerInstanceRef,
    enableStickyHeader,
    enablePagination,
    positionPagination,
    positionToolbarAlertBanner,
    positionToolbarDropZone,
    enableTopToolbar,
    enableBottomToolbar,
    enableKeyboardNavigation,
    onRowOrderChange,
    onRowClick,
    onRowDoubleClick,
    onCellClick,
    onCellDoubleClick,
    renderEmpty,
    renderCaption,
    renderTopToolbar,
    renderBottomToolbar,
    renderBottomToolbarCustomActions,
    localization,
  } = table.cnTable

  const { ref: gridRef, onKeyDown } = useGridNavigation<HTMLDivElement>(
    enableKeyboardNavigation
  )

  const sensors = useSensors(
    useSensor(PointerSensor, { activationConstraint: { distance: 5 } }),
    useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates })
  )

  const padding = DENSITY_CELL_PADDING[density]
  const visibleColumnCount = table.getVisibleLeafColumns().length
  const topRows = table.getTopRows()
  const bottomRows = table.getBottomRows()
  const centerRows = table.getCenterRows()
  const hasRows = topRows.length + centerRows.length + bottomRows.length > 0

  const leafColumnIds = table.getVisibleLeafColumns().map((c) => c.id)
  const centerRowIds = centerRows.map((r) => r.id)

  const anyFilterable = table
    .getAllColumns()
    .some((column) => column.getCanFilter())
  const filterRowVisible =
    enableColumnFilters && showColumnFilters && anyFilterable

  // Render a footer whenever any column defines one; stickiness is separate
  // (controlled by enableStickyFooter, on by default).
  const showFooter = table
    .getAllLeafColumns()
    .some((c) => c.columnDef.footer != null)

  const columnSizing = table.getState().columnSizing
  const columnSizingInfo = table.getState().columnSizingInfo
  const columnSizeVars = React.useMemo(
    () => (enableColumnResizing ? getColumnSizeVars(table) : {}),
    // columnSizing/Info are intentional triggers: recompute vars on resize.
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [enableColumnResizing, table, columnSizing, columnSizingInfo]
  )

  // While resizing, widths come from CSS vars. Otherwise honor an explicitly
  // defined `columnDef.size` (MRT behaviour) but leave unsized columns to the
  // browser's auto layout so the table still fills its container.
  const widthStyle = (column: Column<TData, unknown>): React.CSSProperties => {
    if (enableColumnResizing) return getColumnWidthStyle(column.id)
    // Column virtualization needs every column to have a concrete width.
    if (enableColumnVirtualization || column.columnDef.size != null) {
      const size = column.getSize()
      return { width: size, minWidth: size }
    }
    return {}
  }

  // One DndContext handles both column and row drags; the active item's
  // `data.type` (set in useSortable) routes to the right handler. (Two nested
  // contexts can't be used: dnd-kit renders an a11y <div> that is invalid
  // inside <tbody>, and a body-wrapping context would swallow header drags.)
  const handleDragEnd = (event: DragEndEvent) => {
    const { active, over } = event
    if (!over) return
    const type = active.data.current?.type

    if (type === "row") {
      if (active.id !== over.id) {
        onRowOrderChange?.(active.id as string, over.id as string)
      }
      return
    }

    // column drag
    if (over.id === GROUP_DROPZONE_ID) {
      const column = table.getColumn(active.id as string)
      if (column && !column.getIsGrouped()) column.toggleGrouping()
      return
    }
    if (active.id === over.id) return
    const base =
      table.getState().columnOrder.length > 0
        ? table.getState().columnOrder
        : table.getAllLeafColumns().map((c) => c.id)
    const oldIndex = base.indexOf(active.id as string)
    const newIndex = base.indexOf(over.id as string)
    if (oldIndex === -1 || newIndex === -1) return
    table.setColumnOrder(arrayMove(base, oldIndex, newIndex))
  }

  // Tree data (getSubRows) indents the first real data column by row depth so
  // the hierarchy is visible (grouped rows self-indent via the group cell).
  const isTreeData = table.options.getSubRows != null
  const firstDataColumnId = table
    .getVisibleLeafColumns()
    .find((c) => !NON_DATA_COLUMN_IDS.has(c.id))?.id

  const renderCell = (
    cell: Cell<TData, unknown>,
    row: Row<TData>,
    rowIndex: number,
    colIndex: number
  ) => {
    const align = cell.column.columnDef.meta?.align ?? "left"
    const treeIndent =
      isTreeData &&
      cell.column.id === firstDataColumnId &&
      !cell.getIsGrouped() &&
      row.depth > 0
        ? row.depth
        : 0
    return (
      <TableCell
        key={cell.id}
        data-cell-row={rowIndex}
        data-cell-col={colIndex}
        data-pinned={cell.column.getIsPinned() || undefined}
        tabIndex={
          enableKeyboardNavigation
            ? rowIndex === 0 && colIndex === 0
              ? 0
              : -1
            : undefined
        }
        style={{
          ...widthStyle(cell.column),
          ...getColumnPinningStyle(cell.column),
        }}
        onClick={
          onCellClick
            ? (event) => onCellClick({ cell, row, table, event })
            : undefined
        }
        onDoubleClick={
          onCellDoubleClick
            ? (event) => onCellDoubleClick({ cell, row, table, event })
            : undefined
        }
        className={cn(
          "relative bg-background",
          padding,
          ALIGN_CELL[align],
          getColumnPinningClass(cell.column),
          enableKeyboardNavigation &&
            "focus-visible:ring-2 focus-visible:ring-ring/50 focus-visible:-outline-offset-2 focus-visible:outline-none"
        )}
      >
        {treeIndent > 0 ? (
          <span
            className="flex items-center"
            style={{ paddingInlineStart: `${treeIndent}rem` }}
          >
            {renderBodyCell(
              cell,
              table,
              enableFilterMatchHighlighting,
              columnsWithCustomCell,
              localization
            )}
          </span>
        ) : (
          renderBodyCell(
            cell,
            table,
            enableFilterMatchHighlighting,
            columnsWithCustomCell,
            localization
          )
        )}
      </TableCell>
    )
  }

  const renderCells = (row: Row<TData>, rowIndex: number): React.ReactNode => {
    const cells = row.getVisibleCells()
    if (!enableColumnVirtualization) {
      return cells.map((cell, colIndex) =>
        renderCell(cell, row, rowIndex, colIndex)
      )
    }
    return withColumnSpacers(
      virtualColumns
        .map((vc) => {
          const cell = cells[vc.index]
          return cell ? renderCell(cell, row, rowIndex, vc.index) : null
        })
        .filter(Boolean) as React.ReactNode[],
      `row-${row.id}`
    )
  }

  const renderHeadCell = (header: Header<TData, unknown>) => (
    <DataTableHeadCell
      key={header.id}
      header={header}
      table={table}
      draggable={
        enableColumnOrdering &&
        !enableColumnVirtualization &&
        !DISPLAY_COLUMN_IDS.has(header.column.id) &&
        !header.column.getIsPinned()
      }
      resizable={enableColumnResizing}
      widthStyle={widthStyle(header.column)}
      padding={padding}
    >
      {header.isPlaceholder ? null : (
        <DataTableColumnHeader header={header} table={table} />
      )}
    </DataTableHeadCell>
  )

  const renderFilterCell = (header: Header<TData, unknown>) => (
    <TableHead
      key={header.id}
      colSpan={header.colSpan}
      style={{
        ...widthStyle(header.column),
        ...getColumnPinningStyle(header.column),
      }}
      className={cn(
        "bg-background pt-0 pb-2",
        getColumnPinningClass(header.column)
      )}
    >
      <DataTableColumnFilter header={header} table={table} />
    </TableHead>
  )

  const detailRow = (row: Row<TData>) => (
    <TableRow className="hover:bg-transparent">
      <TableCell colSpan={visibleColumnCount} className="bg-muted/20 p-0">
        <div className="p-3">{renderDetailPanel?.({ row, table })}</div>
      </TableCell>
    </TableRow>
  )

  let runningRowIndex = 0
  const renderRow = (row: Row<TData>) => {
    const rowIndex = runningRowIndex++
    const isGrouped = row.getIsGrouped()
    const showDetail = !!renderDetailPanel && row.getIsExpanded() && !isGrouped

    return (
      <React.Fragment key={row.id}>
        <DataTableBodyRow
          row={row}
          draggable={
            enableRowOrdering &&
            !enableRowVirtualization &&
            !row.getIsPinned() &&
            !isGrouped
          }
          onClick={
            onRowClick
              ? (event) => onRowClick({ row, table, event })
              : undefined
          }
          onDoubleClick={
            onRowDoubleClick
              ? (event) => onRowDoubleClick({ row, table, event })
              : undefined
          }
        >
          {renderCells(row, rowIndex)}
        </DataTableBodyRow>
        {showDetail && detailRow(row)}
      </React.Fragment>
    )
  }

  // Flatten center rows (+ expanded detail panels) into a virtualization list.
  const virtualItems: { row: Row<TData>; detail: boolean }[] = []
  if (enableRowVirtualization) {
    for (const row of centerRows) {
      virtualItems.push({ row, detail: false })
      if (renderDetailPanel && row.getIsExpanded() && !row.getIsGrouped()) {
        virtualItems.push({ row, detail: true })
      }
    }
  }

  // User-supplied passthrough options, resolved from their value-or-function form.
  const rowVOptions =
    typeof rowVirtualizerOptions === "function"
      ? rowVirtualizerOptions({ table })
      : rowVirtualizerOptions
  const columnVOptions =
    typeof columnVirtualizerOptions === "function"
      ? columnVirtualizerOptions({ table })
      : columnVirtualizerOptions

  const rowVirtualizer = useVirtualizer({
    count: virtualItems.length,
    getScrollElement: () => gridRef.current,
    estimateSize: () => table.cnTable.estimateRowHeight,
    overscan: table.cnTable.virtualOverscan,
    measureElement:
      typeof window !== "undefined"
        ? (el) => el?.getBoundingClientRect().height ?? 0
        : undefined,
    ...rowVOptions,
  })

  // Horizontal virtualizer for wide tables. When off, count is 0 and the
  // helpers below fall through to rendering all columns.
  const leafColumns = table.getVisibleLeafColumns()
  const columnVirtualizer = useVirtualizer({
    horizontal: true,
    count: enableColumnVirtualization ? leafColumns.length : 0,
    getScrollElement: () => gridRef.current,
    estimateSize: (index) => leafColumns[index]?.getSize() ?? 150,
    overscan: table.cnTable.virtualOverscan,
    ...columnVOptions,
  })

  // Expose the virtualizer instances for imperative control (e.g. scrollToIndex).
  React.useEffect(() => {
    if (rowVirtualizerInstanceRef) rowVirtualizerInstanceRef.current = rowVirtualizer
  })
  React.useEffect(() => {
    if (columnVirtualizerInstanceRef)
      columnVirtualizerInstanceRef.current = columnVirtualizer
  })
  const virtualColumns = enableColumnVirtualization
    ? columnVirtualizer.getVirtualItems()
    : []
  const colSpacerLeft = virtualColumns.length
    ? (virtualColumns[0]?.start ?? 0)
    : 0
  const colSpacerRight = virtualColumns.length
    ? columnVirtualizer.getTotalSize() -
      (virtualColumns[virtualColumns.length - 1]?.end ?? 0)
    : 0

  /** Wraps a row of cells with left/right spacers when virtualizing columns. */
  const withColumnSpacers = (
    cells: React.ReactNode[],
    keyPrefix: string
  ): React.ReactNode => {
    if (!enableColumnVirtualization) return cells
    return (
      <>
        {colSpacerLeft > 0 && (
          <td
            key={`${keyPrefix}-spacer-l`}
            aria-hidden
            style={{ width: colSpacerLeft }}
          />
        )}
        {cells}
        {colSpacerRight > 0 && (
          <td
            key={`${keyPrefix}-spacer-r`}
            aria-hidden
            style={{ width: colSpacerRight }}
          />
        )}
      </>
    )
  }

  return (
    <TooltipProvider delayDuration={300}>
      <div
        data-slot="data-table"
        className={cn(
          "flex w-full flex-col gap-2",
          isFullscreen &&
            "fixed inset-0 z-50 gap-2 overflow-auto bg-background p-4",
          className
        )}
        data-density={density}
        {...props}
      >
        {renderTopToolbar
          ? renderTopToolbar({ table })
          : enableTopToolbar && <DataTableToolbar table={table} />}
        {positionToolbarAlertBanner === "top" && (
          <DataTableAlertBanner table={table} />
        )}

        {enablePagination &&
          (positionPagination === "top" || positionPagination === "both") && (
            <DataTablePagination
              table={table}
              pageSizeOptions={pageSizeOptions}
            />
          )}

        <DndContext
          sensors={sensors}
          collisionDetection={closestCenter}
          onDragEnd={handleDragEnd}
        >
          {enableGrouping &&
            (positionToolbarDropZone === "top" ||
              positionToolbarDropZone === "both") && (
              <DataTableDropToGroupZone table={table} />
            )}

          <div
            ref={gridRef}
            onKeyDown={onKeyDown}
            data-slot="data-table-surface"
            className={cn(
              // This surface is the single scroll container for both axes, so
              // the sticky header/footer engage and the horizontal scrollbar
              // stays pinned to the visible bottom. Neutralize the shadcn
              // <Table> wrapper's own overflow so it doesn't become a second
              // (unbounded) scroll container that breaks sticky positioning.
              "relative overflow-auto rounded-md border [&>[data-slot=table-container]]:overflow-visible",
              enableRowVirtualization && "max-h-[600px]",
              surfaceClassName
            )}
          >
            {showProgressBars && (
              <div
                data-slot="data-table-progress"
                className="absolute inset-x-0 top-0 z-30 h-0.5 overflow-hidden bg-primary/20"
                role="presentation"
              >
                <div className="h-full w-1/3 animate-[cn-table-progress_1.1s_ease-in-out_infinite] bg-primary" />
              </div>
            )}

            <Table
              style={columnSizeVars}
              // When resizing, size to content but never below the container,
              // so columns fill the width (incl. full-screen) yet can grow to
              // scroll when their combined width exceeds it.
              className={cn(enableColumnResizing && "w-auto min-w-full")}
            >
              {renderCaption && (
                <TableCaption>{renderCaption({ table })}</TableCaption>
              )}
              <TableHeader
                className={cn(
                  enableStickyHeader && "sticky top-0 z-20 bg-background"
                )}
              >
                {table.getHeaderGroups().map((headerGroup) => (
                  <TableRow
                    key={headerGroup.id}
                    className="group/th hover:bg-transparent"
                  >
                    {enableColumnVirtualization ? (
                      withColumnSpacers(
                        virtualColumns
                          .map((vc) => {
                            const header = headerGroup.headers[vc.index]
                            return header ? renderHeadCell(header) : null
                          })
                          .filter(Boolean) as React.ReactNode[],
                        `head-${headerGroup.id}`
                      )
                    ) : (
                      <SortableContext
                        items={leafColumnIds}
                        strategy={horizontalListSortingStrategy}
                      >
                        {headerGroup.headers.map(renderHeadCell)}
                      </SortableContext>
                    )}
                  </TableRow>
                ))}

                {filterRowVisible &&
                  table.getHeaderGroups().map((headerGroup) => (
                    <TableRow
                      key={`${headerGroup.id}-filters`}
                      className="hover:bg-transparent"
                    >
                      {enableColumnVirtualization
                        ? withColumnSpacers(
                            virtualColumns
                              .map((vc) => {
                                const header = headerGroup.headers[vc.index]
                                return header ? renderFilterCell(header) : null
                              })
                              .filter(Boolean) as React.ReactNode[],
                            `filter-${headerGroup.id}`
                          )
                        : headerGroup.headers.map(renderFilterCell)}
                    </TableRow>
                  ))}
              </TableHeader>

              <TableBody>
                {showSkeletons && !hasRows ? (
                  <SkeletonRows
                    rowCount={
                      enablePagination
                        ? table.getState().pagination.pageSize
                        : 8
                    }
                    columnCount={visibleColumnCount}
                    padding={padding}
                  />
                ) : hasRows && enableRowVirtualization ? (
                  <>
                    {topRows.map(renderRow)}
                    {(() => {
                      const vRows = rowVirtualizer.getVirtualItems()
                      const padTop = vRows.length ? (vRows[0]?.start ?? 0) : 0
                      const padBottom = vRows.length
                        ? rowVirtualizer.getTotalSize() -
                          (vRows[vRows.length - 1]?.end ?? 0)
                        : 0
                      return (
                        <>
                          {padTop > 0 && (
                            <tr aria-hidden>
                              <td
                                colSpan={visibleColumnCount}
                                style={{
                                  height: padTop,
                                  padding: 0,
                                  border: 0,
                                }}
                              />
                            </tr>
                          )}
                          {vRows.map((vRow) => {
                            const item = virtualItems[vRow.index]
                            if (!item) return null
                            if (item.detail) {
                              return (
                                <TableRow
                                  key={`${item.row.id}-detail`}
                                  data-index={vRow.index}
                                  ref={rowVirtualizer.measureElement}
                                  className="hover:bg-transparent"
                                >
                                  <TableCell
                                    colSpan={visibleColumnCount}
                                    className="bg-muted/20 p-0"
                                  >
                                    <div className="p-3">
                                      {renderDetailPanel?.({
                                        row: item.row,
                                        table,
                                      })}
                                    </div>
                                  </TableCell>
                                </TableRow>
                              )
                            }
                            return (
                              <TableRow
                                key={item.row.id}
                                data-index={vRow.index}
                                ref={rowVirtualizer.measureElement}
                                data-state={
                                  item.row.getIsSelected()
                                    ? "selected"
                                    : undefined
                                }
                                onClick={
                                  onRowClick
                                    ? (event) =>
                                        onRowClick({
                                          row: item.row,
                                          table,
                                          event,
                                        })
                                    : undefined
                                }
                                onDoubleClick={
                                  onRowDoubleClick
                                    ? (event) =>
                                        onRowDoubleClick({
                                          row: item.row,
                                          table,
                                          event,
                                        })
                                    : undefined
                                }
                                className={cn(
                                  "data-[state=selected]:shadow-[inset_2px_0_0_0_var(--primary)]",
                                  (onRowClick || onRowDoubleClick) &&
                                    "cursor-pointer"
                                )}
                              >
                                {renderCells(item.row, vRow.index)}
                              </TableRow>
                            )
                          })}
                          {padBottom > 0 && (
                            <tr aria-hidden>
                              <td
                                colSpan={visibleColumnCount}
                                style={{
                                  height: padBottom,
                                  padding: 0,
                                  border: 0,
                                }}
                              />
                            </tr>
                          )}
                        </>
                      )
                    })()}
                    {bottomRows.map(renderRow)}
                  </>
                ) : hasRows ? (
                  <>
                    {topRows.map(renderRow)}
                    <SortableContext
                      items={centerRowIds}
                      strategy={verticalListSortingStrategy}
                    >
                      {centerRows.map(renderRow)}
                    </SortableContext>
                    {bottomRows.map(renderRow)}
                  </>
                ) : (
                  <TableRow className="hover:bg-transparent">
                    <TableCell
                      colSpan={visibleColumnCount}
                      className="h-32 text-center text-sm text-muted-foreground"
                    >
                      {renderEmpty?.({ table }) ??
                        localization.noRecordsToDisplay}
                    </TableCell>
                  </TableRow>
                )}
              </TableBody>

              {showFooter && (
                <TableFooter
                  className={cn(enableStickyFooter && "sticky bottom-0 z-20")}
                >
                  {table.getFooterGroups().map((footerGroup) => {
                    const headers = enableColumnVirtualization
                      ? (virtualColumns
                          .map((vc) => footerGroup.headers[vc.index])
                          .filter(Boolean) as Header<TData, unknown>[])
                      : footerGroup.headers
                    const cells = headers.map((header) => (
                      <TableCell
                        key={header.id}
                        colSpan={header.colSpan}
                        style={{
                          ...widthStyle(header.column),
                          ...getColumnPinningStyle(header.column),
                        }}
                        className={cn(
                          padding,
                          getColumnPinningClass(header.column)
                        )}
                      >
                        {header.isPlaceholder
                          ? null
                          : flexRender(
                              header.column.columnDef.footer,
                              header.getContext()
                            )}
                      </TableCell>
                    ))
                    return (
                      <TableRow
                        key={footerGroup.id}
                        className="hover:bg-transparent"
                      >
                        {withColumnSpacers(cells, `footer-${footerGroup.id}`)}
                      </TableRow>
                    )
                  })}
                </TableFooter>
              )}
            </Table>

            {showLoadingOverlay && hasRows && (
              <div
                className="absolute inset-0 z-10 bg-background/40"
                aria-hidden
              />
            )}
          </div>

          {enableGrouping &&
            (positionToolbarDropZone === "bottom" ||
              positionToolbarDropZone === "both") && (
              <DataTableDropToGroupZone table={table} />
            )}
        </DndContext>

        {positionToolbarAlertBanner === "bottom" && (
          <DataTableAlertBanner table={table} />
        )}

        {renderBottomToolbar
          ? renderBottomToolbar({ table })
          : enableBottomToolbar &&
            (() => {
              const customActions = renderBottomToolbarCustomActions?.({
                table,
              })
              const showBottomPagination =
                enablePagination &&
                (positionPagination === "bottom" ||
                  positionPagination === "both")
              const pagination = showBottomPagination ? (
                <DataTablePagination
                  table={table}
                  pageSizeOptions={pageSizeOptions}
                />
              ) : null
              if (customActions == null) return pagination
              return (
                <div
                  data-slot="data-table-bottom-toolbar"
                  className="flex flex-wrap items-center justify-between gap-4"
                >
                  <div className="flex items-center gap-2">{customActions}</div>
                  {pagination && <div className="flex-1">{pagination}</div>}
                </div>
              )
            })()}

        <DataTableEditModal table={table} />
      </div>
    </TooltipProvider>
  )
}

function SkeletonRows({
  rowCount,
  columnCount,
  padding,
}: {
  rowCount: number
  columnCount: number
  padding: string
}) {
  return (
    <>
      {Array.from({ length: Math.max(1, rowCount) }).map((_, rowIndex) => (
        <TableRow key={rowIndex} className="hover:bg-transparent">
          {Array.from({ length: Math.max(1, columnCount) }).map(
            (__, colIndex) => (
              <TableCell key={colIndex} className={padding}>
                <Skeleton className="h-4 w-full max-w-[12rem]" />
              </TableCell>
            )
          )}
        </TableRow>
      ))}
    </>
  )
}

/**
 * Resolves a body cell's content, handling grouped / aggregated / placeholder
 * cells and falling back to the highlight-aware value renderer.
 */
function renderBodyCell<TData extends RowData>(
  cell: Cell<TData, unknown>,
  table: DataTableInstance<TData>,
  enableHighlight: boolean,
  columnsWithCustomCell: ReadonlySet<string>,
  localization: DataTableInstance<TData>["cnTable"]["localization"]
): React.ReactNode {
  const { row, column } = cell
  const icons = table.cnTable.icons
  const meta = column.columnDef.meta

  // Grouped/aggregated/placeholder cells are a grouping concept. Tree data
  // (getSubRows) also marks parent rows' cells as "aggregated", which would
  // bypass normal cell rendering (e.g. the expand chevron). Only take these
  // branches when grouping is actually active.
  const isGrouping = table.getState().grouping.length > 0

  if (isGrouping && cell.getIsGrouped()) {
    return (
      <button
        type="button"
        aria-label={localization.toggleRowExpanded}
        aria-expanded={row.getIsExpanded()}
        onClick={row.getToggleExpandedHandler()}
        style={{ paddingInlineStart: `${row.depth * 1}rem` }}
        className="flex items-center gap-1.5 text-left outline-none focus-visible:ring-2 focus-visible:ring-ring/40"
      >
        {row.getIsExpanded() ? (
          <icons.expanded className="size-4 shrink-0 text-muted-foreground" />
        ) : (
          <icons.collapsed className="size-4 shrink-0 text-muted-foreground" />
        )}
        <span className="font-medium">
          {meta?.renderGroupedCell
            ? meta.renderGroupedCell({ cell, row, column, table })
            : flexRender(column.columnDef.cell, cell.getContext())}
        </span>
        <span className="text-xs text-muted-foreground">
          ({row.subRows.length})
        </span>
      </button>
    )
  }

  if (isGrouping && cell.getIsAggregated()) {
    if (meta?.renderAggregatedCell) {
      return meta.renderAggregatedCell({ cell, row, column, table })
    }
    return flexRender(
      column.columnDef.aggregatedCell ?? column.columnDef.cell,
      cell.getContext()
    )
  }

  if (isGrouping && cell.getIsPlaceholder()) {
    return meta?.renderPlaceholderCell
      ? meta.renderPlaceholderCell({ cell, row, column, table })
      : null
  }

  return (
    <DataTableBodyCellContent
      cell={cell}
      table={table}
      fallback={renderCellContent(
        cell,
        table,
        enableHighlight,
        columnsWithCustomCell
      )}
    />
  )
}

/**
 * Renders a cell's value, auto-highlighting matched substrings for columns with
 * no custom cell renderer and an active string substring filter / global query.
 */
function renderCellContent<TData extends RowData>(
  cell: Cell<TData, unknown>,
  table: DataTableInstance<TData>,
  enableHighlight: boolean,
  columnsWithCustomCell: ReadonlySet<string>
): React.ReactNode {
  const { column } = cell
  const value = cell.getValue()
  const canHighlight =
    enableHighlight &&
    !column.columnDef.meta?.disableHighlight &&
    !columnsWithCustomCell.has(column.id) &&
    (typeof value === "string" || typeof value === "number")

  if (canHighlight) {
    const query = resolveHighlightQuery(cell, table)
    if (query) {
      return <Highlight text={String(value)} query={query} />
    }
  }

  return flexRender(column.columnDef.cell, cell.getContext())
}

/** The active highlight query for a cell: its column filter, else global search. */
function resolveHighlightQuery<TData extends RowData>(
  cell: Cell<TData, unknown>,
  table: DataTableInstance<TData>
): string | null {
  const filterValue = cell.column.getFilterValue()
  if (
    typeof filterValue === "string" &&
    filterValue.length > 0 &&
    SUBSTRING_MODES.has(getEffectiveMode(cell.column, table))
  ) {
    return filterValue
  }
  const globalFilter = table.getState().globalFilter
  if (
    typeof globalFilter === "string" &&
    globalFilter.length > 0 &&
    SUBSTRING_MODES.has(table.cnTable.globalFilterMode)
  ) {
    return globalFilter
  }
  return null
}

"use client"

import * as React from "react"
import type { ColumnDef, RowData } from "@tanstack/react-table"

import { cn } from "@/lib/utils"

import type { DataTableIcons, IconComponent } from "./icons"
import type { DataTableLocalization } from "./localization"

export const ROW_NUMBER_COLUMN_ID = "cn-row-number"
export const ROW_DRAG_COLUMN_ID = "cn-row-drag"
export const EXPAND_COLUMN_ID = "cn-expand"

/** Expand/collapse column for detail panels and tree (sub-row) expansion. */
export function createExpandColumn<TData extends RowData>(
  localization: DataTableLocalization,
  icons: DataTableIcons
): ColumnDef<TData> {
  return {
    id: EXPAND_COLUMN_ID,
    enableSorting: false,
    enableHiding: false,
    enableColumnFilter: false,
    enableResizing: false,
    size: 44,
    minSize: 44,
    meta: { disableColumnActions: true },
    header: ({ table }) =>
      table.getCanSomeRowsExpand() ? (
        <button
          type="button"
          aria-label={localization.expandAll}
          onClick={table.getToggleAllRowsExpandedHandler()}
          className="flex items-center justify-center text-muted-foreground transition-colors outline-none hover:text-foreground focus-visible:ring-2 focus-visible:ring-ring/40"
        >
          {table.getIsAllRowsExpanded() ? (
            <icons.expanded className="size-4" />
          ) : (
            <icons.collapsed className="size-4" />
          )}
        </button>
      ) : null,
    cell: ({ row }) => {
      if (!row.getCanExpand()) return null
      return (
        <button
          type="button"
          aria-label={localization.toggleRowExpanded}
          aria-expanded={row.getIsExpanded()}
          onClick={row.getToggleExpandedHandler()}
          className="flex items-center justify-center text-muted-foreground transition-colors outline-none hover:text-foreground focus-visible:ring-2 focus-visible:ring-ring/40"
        >
          {row.getIsExpanded() ? (
            <icons.expanded className="size-4" />
          ) : (
            <icons.collapsed className="size-4" />
          )}
        </button>
      )
    },
  }
}

/** dnd-kit activator props for the current row's drag handle. */
export interface RowDragHandleProps {
  attributes: Record<string, unknown>
  listeners: Record<string, unknown> | undefined
  setActivatorNodeRef: (el: HTMLElement | null) => void
}

export const RowDragContext = React.createContext<RowDragHandleProps | null>(
  null
)

/** Drag-handle column for row ordering. The handle reads dnd-kit props from
 *  {@link RowDragContext}, set by the sortable row wrapper. */
export function createRowDragHandleColumn<TData extends RowData>(
  localization: DataTableLocalization,
  icons: DataTableIcons
): ColumnDef<TData> {
  return {
    id: ROW_DRAG_COLUMN_ID,
    enableSorting: false,
    enableHiding: false,
    enableColumnFilter: false,
    enableResizing: false,
    size: 40,
    minSize: 40,
    meta: { disableColumnActions: true, align: "center" },
    header: () => null,
    cell: () => (
      <RowDragHandle label={localization.reorderRow} Icon={icons.dragHandle} />
    ),
  }
}

function RowDragHandle({
  label,
  Icon,
}: {
  label: string
  Icon: IconComponent
}) {
  const ctx = React.useContext(RowDragContext)
  return (
    <button
      type="button"
      aria-label={label}
      ref={ctx?.setActivatorNodeRef}
      suppressHydrationWarning
      {...(ctx?.attributes ?? {})}
      {...(ctx?.listeners ?? {})}
      className="flex cursor-grab items-center justify-center text-muted-foreground transition-colors outline-none hover:text-foreground focus-visible:ring-2 focus-visible:ring-ring/40 active:cursor-grabbing"
    >
      <Icon className="size-4" />
    </button>
  )
}

/** Row-number column. `static` numbers track the current view (page-aware);
 *  `original` uses the stable source index. Optionally shows a pin toggle. */
export function createRowNumberColumn<TData extends RowData>(
  localization: DataTableLocalization,
  mode: "static" | "original",
  enableRowPinning: boolean,
  icons: DataTableIcons
): ColumnDef<TData> {
  return {
    id: ROW_NUMBER_COLUMN_ID,
    enableSorting: false,
    enableHiding: false,
    enableColumnFilter: false,
    enableResizing: false,
    size: 56,
    minSize: 48,
    meta: { disableColumnActions: true, align: "center", label: "#" },
    header: () => <span className="text-muted-foreground">#</span>,
    cell: ({ row, table }) => {
      const number =
        mode === "original"
          ? row.index + 1
          : table.getRowModel().rows.indexOf(row) +
            1 +
            table.getState().pagination.pageIndex *
              table.getState().pagination.pageSize

      if (!enableRowPinning) {
        return (
          <span className="text-xs tabular-nums text-muted-foreground">
            {number}
          </span>
        )
      }

      const pinned = row.getIsPinned()
      return (
        <span className="group/rownum relative flex items-center justify-center">
          <span
            className={cn(
              "text-xs tabular-nums text-muted-foreground",
              "group-hover/rownum:opacity-0"
            )}
          >
            {number}
          </span>
          <button
            type="button"
            aria-label={pinned ? localization.unpinRow : localization.pinRow}
            onClick={() => row.pin(pinned ? false : "top")}
            className={cn(
              "absolute inset-0 flex items-center justify-center text-muted-foreground opacity-0 transition-opacity hover:text-foreground focus-visible:opacity-100 group-hover/rownum:opacity-100",
              pinned && "text-primary opacity-100"
            )}
          >
            {pinned ? (
              <icons.pinnedRow className="size-3.5" />
            ) : (
              <icons.pin className="size-3.5" />
            )}
          </button>
        </span>
      )
    },
  }
}

import type { Column, Row, RowData } from "@tanstack/react-table"
import Papa from "papaparse"
import * as XLSX from "xlsx"

import { getColumnLabel } from "./data-table-column-actions"
import { EXPAND_COLUMN_ID, ROW_DRAG_COLUMN_ID, ROW_NUMBER_COLUMN_ID } from "./display-columns"
import { ROW_ACTIONS_COLUMN_ID } from "./data-table-row-actions"
import { SELECTION_COLUMN_ID } from "./selection-column"
import type { DataTableInstance } from "./types"

const NON_DATA_COLUMNS = new Set([
  SELECTION_COLUMN_ID,
  ROW_NUMBER_COLUMN_ID,
  ROW_DRAG_COLUMN_ID,
  EXPAND_COLUMN_ID,
  ROW_ACTIONS_COLUMN_ID,
])

/** Which rows to export. */
export type ExportScope = "selected" | "filtered" | "all" | "page"

export interface ExportOptions {
  fileName?: string
  /** Defaults to "selected" when rows are selected, else "filtered". */
  scope?: ExportScope
}

/** Data columns suitable for export (excludes the injected display columns). */
export function getExportableColumns<TData extends RowData>(
  table: DataTableInstance<TData>
): Column<TData, unknown>[] {
  return table
    .getVisibleLeafColumns()
    .filter((column) => column.accessorFn != null && !NON_DATA_COLUMNS.has(column.id))
}

function resolveRows<TData extends RowData>(
  table: DataTableInstance<TData>,
  scope: ExportScope
): Row<TData>[] {
  switch (scope) {
    case "selected":
      return table.getSelectedRowModel().rows
    case "page":
      return table.getRowModel().rows
    case "all":
      return table.getPreFilteredRowModel().rows
    default:
      return table.getFilteredRowModel().rows
  }
}

function effectiveScope<TData extends RowData>(
  table: DataTableInstance<TData>,
  scope?: ExportScope
): ExportScope {
  if (scope) return scope
  return table.getSelectedRowModel().rows.length > 0 ? "selected" : "filtered"
}

/** Builds an array-of-arrays: [header labels, ...data rows] of raw values. */
export function toAOA<TData extends RowData>(
  table: DataTableInstance<TData>,
  scope: ExportScope
): (string | number | boolean | null)[][] {
  const columns = getExportableColumns(table)
  const header = columns.map((column) => getColumnLabel(column))
  const rows = resolveRows(table, scope).map((row) =>
    columns.map((column) => normalize(row.getValue(column.id)))
  )
  return [header, ...rows]
}

function normalize(value: unknown): string | number | boolean | null {
  if (value == null) return null
  if (
    typeof value === "number" ||
    typeof value === "boolean" ||
    typeof value === "string"
  ) {
    return value
  }
  if (value instanceof Date) return value.toISOString()
  return String(value)
}

/** Export to CSV via PapaParse + a Blob download. */
export function exportToCsv<TData extends RowData>(
  table: DataTableInstance<TData>,
  options: ExportOptions = {}
): void {
  const scope = effectiveScope(table, options.scope)
  const aoa = toAOA(table, scope)
  const csv = Papa.unparse(aoa)
  // Prepend a UTF-8 BOM so Excel detects the encoding.
  const blob = new Blob(["\uFEFF" + csv], { type: "text/csv;charset=utf-8;" })
  triggerDownload(blob, `${options.fileName ?? "export"}.csv`)
}

/** Export to an .xlsx worksheet via SheetJS. */
export function exportToExcel<TData extends RowData>(
  table: DataTableInstance<TData>,
  options: ExportOptions = {}
): void {
  const scope = effectiveScope(table, options.scope)
  const aoa = toAOA(table, scope)
  const worksheet = XLSX.utils.aoa_to_sheet(aoa)
  const workbook = XLSX.utils.book_new()
  XLSX.utils.book_append_sheet(workbook, worksheet, "Sheet1")
  XLSX.writeFile(workbook, `${options.fileName ?? "export"}.xlsx`)
}

function triggerDownload(blob: Blob, fileName: string): void {
  if (typeof document === "undefined") return
  const url = URL.createObjectURL(blob)
  const link = document.createElement("a")
  link.href = url
  link.download = fileName
  document.body.appendChild(link)
  link.click()
  document.body.removeChild(link)
  URL.revokeObjectURL(url)
}

import type { FilterFn, RowData } from "@tanstack/react-table"
import { rankItem } from "@tanstack/match-sorter-utils"
import { isAfter, isBefore, startOfDay } from "date-fns"

import type { FilterVariant } from "./types"

/** Global-search modes offered in the global filter-mode menu. */
export type GlobalFilterMode =
  | "fuzzy"
  | "contains"
  | "startsWith"
  | "endsWith"
  | "equals"

/** All supported filter modes across variants. */
export type FilterMode =
  // text
  | "contains"
  | "equals"
  | "notEquals"
  | "startsWith"
  | "endsWith"
  | "fuzzy"
  // shared
  | "empty"
  | "notEmpty"
  // numeric
  | "between"
  | "betweenInclusive"
  | "greaterThan"
  | "greaterThanOrEqualTo"
  | "lessThan"
  | "lessThanOrEqualTo"
  // date
  | "before"
  | "after"
  | "betweenDates"
  // fixed (no mode menu)
  | "equalsString"
  | "arrIncludesSome"
  | "equalsBool"

const str = (v: unknown): string => (v == null ? "" : String(v))
const lower = (v: unknown): string => str(v).toLowerCase()
const num = (v: unknown): number =>
  typeof v === "number" ? v : parseFloat(str(v))
const isBlank = (v: unknown): boolean =>
  v == null || v === "" || (Array.isArray(v) && v.length === 0)
const toDate = (v: unknown): Date | null => {
  if (v == null || v === "") return null
  const d = v instanceof Date ? v : new Date(v as string)
  return Number.isNaN(d.getTime()) ? null : d
}

// Each entry: (row value already resolved) decides inclusion. The dynamic
// `filterFn` below resolves `row.getValue(columnId)` and dispatches by mode.
type ModeFn = (cellValue: unknown, filterValue: unknown) => boolean

const MODE_FNS: Record<FilterMode, ModeFn> = {
  contains: (cell, val) => lower(cell).includes(lower(val)),
  equals: (cell, val) => lower(cell) === lower(val),
  notEquals: (cell, val) => lower(cell) !== lower(val),
  startsWith: (cell, val) => lower(cell).startsWith(lower(val)),
  endsWith: (cell, val) => lower(cell).endsWith(lower(val)),
  fuzzy: (cell, val) => lower(cell).includes(lower(val)),

  empty: (cell) => isBlank(cell),
  notEmpty: (cell) => !isBlank(cell),

  greaterThan: (cell, val) => num(cell) > num(val),
  greaterThanOrEqualTo: (cell, val) => num(cell) >= num(val),
  lessThan: (cell, val) => num(cell) < num(val),
  lessThanOrEqualTo: (cell, val) => num(cell) <= num(val),
  between: (cell, val) => betweenNum(cell, val, false),
  betweenInclusive: (cell, val) => betweenNum(cell, val, true),

  before: (cell, val) => {
    const c = toDate(cell)
    const v = toDate(val)
    return c != null && v != null && isBefore(c, startOfDay(v))
  },
  after: (cell, val) => {
    const c = toDate(cell)
    const v = toDate(val)
    return c != null && v != null && isAfter(c, startOfDay(v))
  },
  betweenDates: (cell, val) => {
    const c = toDate(cell)
    const range = (Array.isArray(val) ? val : []) as unknown[]
    const from = toDate(range[0])
    const to = toDate(range[1])
    if (c == null) return false
    if (from != null && isBefore(c, startOfDay(from))) return false
    if (to != null && isAfter(c, startOfDay(to))) return false
    return from != null || to != null
  },

  equalsString: (cell, val) => str(cell) === str(val),
  arrIncludesSome: (cell, val) => {
    const arr = (Array.isArray(val) ? val : []) as unknown[]
    if (arr.length === 0) return true
    return arr.map(str).includes(str(cell))
  },
  equalsBool: (cell, val) => Boolean(cell) === Boolean(val),
}

function betweenNum(cell: unknown, val: unknown, inclusive: boolean): boolean {
  const arr = (Array.isArray(val) ? val : []) as unknown[]
  const n = num(cell)
  if (Number.isNaN(n)) return false
  const min = arr[0] === "" || arr[0] == null ? null : num(arr[0])
  const max = arr[1] === "" || arr[1] == null ? null : num(arr[1])
  if (min != null && (inclusive ? n < min : n <= min)) return false
  if (max != null && (inclusive ? n > max : n >= max)) return false
  return min != null || max != null
}

/** Modes that activate without a typed value (they test the cell only). */
export const VALUELESS_MODES: ReadonlySet<FilterMode> = new Set([
  "empty",
  "notEmpty",
])

/** Modes whose string value should drive match highlighting in cells. */
export const SUBSTRING_MODES: ReadonlySet<FilterMode> = new Set([
  "contains",
  "startsWith",
  "endsWith",
  "equals",
  "fuzzy",
])

/**
 * A value is "inactive" (filter should auto-remove) when blank — unless the
 * mode is valueless, where any truthy sentinel keeps it active.
 */
function isInactive(value: unknown): boolean {
  if (Array.isArray(value)) return value.every((v) => v == null || v === "")
  return value == null || value === ""
}

/**
 * Single dynamic filter function assigned to every column via `defaultColumn`.
 * It reads the column's current mode from the provided lookup and dispatches.
 * Mode state lives in the hook; this closure reads it through `getMode` (a ref
 * getter) so the function identity stays stable across renders.
 */
export function createDynamicFilterFn<TData extends RowData>(
  getMode: (columnId: string) => FilterMode
): FilterFn<TData> {
  const fn: FilterFn<TData> = (row, columnId, filterValue) => {
    const mode = getMode(columnId)
    const modeFn = MODE_FNS[mode] ?? MODE_FNS.contains
    return modeFn(row.getValue(columnId), filterValue)
  }
  // Keep valueless modes active even with a blank value; otherwise drop blanks.
  fn.autoRemove = (value) => isInactive(value)
  return fn
}

/**
 * Mode-aware global search. `fuzzy` uses match-sorter's `rankItem` (MRT's own
 * choice); other modes reuse the column mode functions. Matches across every
 * searchable column (TanStack runs this per column and ORs the results).
 */
export function createGlobalFilterFn<TData extends RowData>(
  getMode: () => GlobalFilterMode
): FilterFn<TData> {
  const fn: FilterFn<TData> = (row, columnId, filterValue) => {
    const value = String(filterValue ?? "")
    if (value === "") return true
    const mode = getMode()
    if (mode === "fuzzy") {
      return rankItem(row.getValue(columnId), value).passed
    }
    const modeFn = MODE_FNS[mode] ?? MODE_FNS.contains
    return modeFn(row.getValue(columnId), value)
  }
  fn.autoRemove = (value) => value == null || value === ""
  return fn
}

/** Default mode for a variant when the consumer hasn't chosen one. */
export function defaultModeForVariant(variant: FilterVariant): FilterMode {
  switch (variant) {
    case "range":
    case "range-slider":
      return "between"
    case "date":
      return "equals"
    case "date-range":
      return "betweenDates"
    case "select":
      return "equalsString"
    case "multi-select":
      return "arrIncludesSome"
    case "checkbox":
      return "equalsBool"
    default:
      return "contains"
  }
}

/** Modes offered in the mode menu per variant. Empty array → no mode menu. */
export function modeOptionsForVariant(variant: FilterVariant): FilterMode[] {
  switch (variant) {
    case "text":
      return [
        "fuzzy",
        "contains",
        "startsWith",
        "endsWith",
        "equals",
        "notEquals",
        "empty",
        "notEmpty",
      ]
    case "range":
    case "range-slider":
      return [
        "between",
        "betweenInclusive",
        "equals",
        "notEquals",
        "greaterThan",
        "greaterThanOrEqualTo",
        "lessThan",
        "lessThanOrEqualTo",
        "empty",
        "notEmpty",
      ]
    case "date":
    case "date-range":
      return [
        "equals",
        "notEquals",
        "before",
        "after",
        "betweenDates",
        "empty",
        "notEmpty",
      ]
    default:
      // select / multi-select / checkbox have a single fixed mode
      return []
  }
}

import * as React from "react"

import { cn } from "@/lib/utils"

const MAX_HIGHLIGHT_LENGTH = 2000

function escapeRegExp(input: string): string {
  return input.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")
}

/**
 * Wraps occurrences of `query` within `text` in a themeable `<mark>`. Work is
 * skipped when there's no query, the query is escaped, and very long strings
 * are left unhighlighted to avoid regex blowups on huge cells.
 */
export const Highlight = React.memo(function Highlight({
  text,
  query,
  className,
}: {
  text: string
  query?: string | null
  className?: string
}) {
  const trimmed = query?.trim()
  if (
    !trimmed ||
    text.length === 0 ||
    text.length > MAX_HIGHLIGHT_LENGTH
  ) {
    return <>{text}</>
  }

  const parts = text.split(new RegExp(`(${escapeRegExp(trimmed)})`, "gi"))
  if (parts.length === 1) return <>{text}</>

  const needle = trimmed.toLowerCase()
  return (
    <>
      {parts.map((part, index) =>
        part.toLowerCase() === needle ? (
          <mark
            key={index}
            className={cn(
              "rounded-[2px] bg-highlight px-0.5 text-highlight-foreground",
              className
            )}
          >
            {part}
          </mark>
        ) : (
          <React.Fragment key={index}>{part}</React.Fragment>
        )
      )}
    </>
  )
})

